window.BOOK_VOLUMES["juan31-xubian-liu"] = {"id": "juan31-xubian-liu", "book": 3, "juan": 31, "primary": "续编六", "secondary": "", "title": "卷31 续编六", "start_page": 2579, "end_page": 2737, "block_count": 317, "blocks": [{"type": "heading", "wen": "征藩公移上", "bai": "", "page": 2579}, {"type": "heading", "wen": "凡二十九条", "bai": "", "page": 2579}, {"type": "heading", "wen": "行吉安府收囤兑粮牌", "bai": "", "page": 2579}, {"type": "meta", "wen": "正德十四年六月二十日", "bai": "", "page": 2579}, {"type": "para", "wen": "据赣县、兴国、永新等县县丞等官李富、雷鸣岳等呈称：“各蒙差押粮里装运，正德十三年兑淮米到于吉安水次，听候交兑，经今数月，未见粮船回还。况今省城变乱，被将各处兑米尽行搬用，恐被奸人乘机越来搬抢”等因到院。为照所呈，系于兑淮钱粮，合行处置。为此抄案仰回府，即便处置空间仓廒，或宽敞寺观去处，令各粮里暂将运来兑淮粮米收囤，候官军回日，听其交兑，毋得迟误，致有他虞。仍行管粮官知会。", "bai": "", "page": 2579}, {"type": "heading", "wen": "行吉安府禁止镇守贡献牌", "bai": "", "page": 2580}, {"type": "heading", "wen": "六月二十日", "bai": "", "page": 2580}, {"type": "para", "wen": "据吉安府守御千户所旗甲马思禀称“蒙所批差，领解镇守江西太监王发买葛布银三封，及本所出备葛布折银并贡礼银三千两，前赴本镇。今因途阻，不敢前去”等情。参照该所掌印官，既该镇守衙门发银买布，若势不容已，只合照价两平收买为当。乃敢不动原封，分外备办礼银馈送，若非设计巧取，必是科克旗军，事属违法，本当参拿究问。但今江西变乱，姑行从轻查理。为此牌仰吉安府，即查前项布价并贡献礼银，务见的确。如称各军名下粮银，就仰会同该所，唱名给散，取领备照。若是各官自行出备，合仰收入官库，听候军饷支用，毋得纵容侵收入己，及查报不实未便。", "bai": "", "page": 2580}, {"type": "heading", "wen": "行福建布政司调兵勤王", "bai": "", "page": 2581}, {"type": "para", "wen": "及照福建、浙江系江西邻省，今宁府逆谋既著，彼若北趋不遂，必将还取闽、浙，若不先行发兵，乘间捣虚，将来之噬脐何及。除行湖广、广东及行漳南道，即将见在上杭教场操练兵快，并取漳州铳手李栋等，责委谋勇官员统领，直抵本院驻扎吉安府，随兵进剿外。仰抄案回司，会行都、按二司转行各道，并行镇巡等衙门，各一体查照知会，选调兵马，选委忠勇胆略堂上官，督领各项交界地方，加谨防截，相机夹剿。仍知会浙江都、布、按三司一体遵照施行，俱毋违错。", "bai": "", "page": 2582}, {"type": "heading", "wen": "预行南京各衙门勤王咨", "bai": "", "page": 2582}, {"type": "para", "wen": "为照前事系天下非常之变，宗社安危之机，虽今备行江西吉安等府，及湖广、福建、广东等处，调集军兵，合势征剿外。但彼声言欲遂顺流东下，窃据南都。看得长江天险，南北之限，留都根本，咽喉所关，虽以朝廷威德，人心效顺，逆谋断无有成。但其谲奸阴图，已非一日，兼闻潜伏奸细于京城，期为内应，万一预备无素，为彼所掩，震惊远迩，噬脐何及！为此合咨贵部，烦为通行在京及大小衙门，会谋集议，作急缮完城守，简练舟师，设伏沿江，以防不虞之袭；传檄傍郡，以张必讨之威；先发操江之兵，声义而西，约会湖湘，互为犄角。本职亦砥钝策驽，牵蹑其后，以义取暴，以直加曲，不过两月之间，断然一鼓可缚，惟高明速图之。", "bai": "", "page": 2583}, {"type": "heading", "wen": "抚安百姓告示", "bai": "", "page": 2584}, {"type": "meta", "wen": "六月二十二日", "bai": "", "page": 2584}, {"type": "para", "wen": "示仰远近城郭乡村军民人等，近日倡乱之徒，上逆天道，下失人心，本院驻军于此，已有定计，勤王之师，四面已集。仰各安居乐业，毋得惊疑，敢有擅自搬移，因而扇惑扰攘者，地方里甲人等绑赴军门，治以军法。其有忠义豪杰，能献计效力，愿从义师击反叛者，俱赴军门投见。", "bai": "", "page": 2584}, {"type": "heading", "wen": "差官调发梅花等峒义兵牌", "bai": "", "page": 2584}, {"type": "heading", "wen": "六月二十七日", "bai": "", "page": 2584}, {"type": "para", "wen": "近因省城遭变，戕害守臣，正人心思奋，忠义效用之时。访得永新县梅花峒及龙田、上乡、樟枧、关北诸处，人民精悍，见义能勇，拟合起调。为此今差千户高睿赍牌前去该县，著落知县柯相，即便起集梅花峒等乡精勇民兵，大约一千名，各备便用坚利器械，选差该乡义官良民部领，就委该县谋勇胆略官一员总领。其合用行粮或募役之费，就于本县在官钱粮查支，不分雨夜，兼程前进军门，听候调遣。此系紧急事理，毋比寻常贼情，敢有故违，定以军法从事。", "bai": "", "page": 2585}, {"type": "heading", "wen": "行吉安府踏勘灾伤", "bai": "", "page": 2586}, {"type": "meta", "wen": "七月初五日", "bai": "", "page": 2586}, {"type": "para", "wen": "照得本院驻兵吉安，节据庐陵等县人民告称：“自五月以来，天时亢旱，田禾枯死，衣食无所仰给，税粮难以措办，近蒙佥点民兵，保守把截，农业既妨，天时不利，人心惶惶，莫知所依”等因到院。参照迩者省城反叛，煽动军民，各属调发官军，佥点民壮，保障城池，把绝要隘，团结保甲，随同征进，人皆为兵，不暇耕种，况兼三月不雨，四郊赤地，民之危急，莫甚于此。本院除具题外。为此仰抄案回府，著落掌印正官，即便亲临踏看灾伤，轻重分数，复查相同，取具乡都里老及官吏不致扶同重甘结状，申报本院，火速径自差人具奏。本年各项钱粮，暂且停征，候命下之日，另行区处，毋得迁延坐视，重贻民患，取究不便。", "bai": "", "page": 2586}, {"type": "heading", "wen": "行吉安府知会纪功御史牌", "bai": "", "page": 2587}, {"type": "heading", "wen": "七月初八日", "bai": "", "page": 2587}, {"type": "para", "wen": "照得江西宁府据城谋叛云云。仰抄案回府，即便备行巡按两广监察谢御史、伍御史查照知会。凡军中一应事宜，悉要本官赞理区画，以匡本院之不逮。各哨官兵，俱听监督。获有功次，俱凭本院送发，本官验实纪录。官兵人等，但有骚扰所过地方，及军前逗遛观望，畏避退缩者，就行照依本院钦奉敕谕事理，治以军法。抄案官吏，具行过日期，同依准申缴。", "bai": "", "page": 2587}, {"type": "heading", "wen": "行知县刘守绪等袭剿坟厂牌七月十三日", "bai": "", "page": 2588}, {"type": "para", "wen": "为照本院亲督诸军，刻期于本月二十日进攻南昌府省城，以破逆党巢穴。探得逆党先曾伏兵三千于老坟厂、新坟厂诸处，以为省城应援，若不先行密为扑剿，诚恐攻城之日，或从间道掩袭我师，未免亦为牵制。为此牌仰奉新县知县刘守绪，靖安县知县万士贤，各统精兵三千，密于西山地界约会刻期分哨设伏运奇，并力夹剿。各官务要详察险易，相度机宜，不得尔先我后，力散势分，致有疏失。仍一面差人爪探声息，飞报军门，擒斩功次，审验解院，转发纪录，照例具奏升赏。兵快人等，敢有临阵退缩者，许照本院钦奉敕谕事理，就以军法从事。各官务竭忠贞，以勤国难，苟或观望逗遛，违误事机，军令具存，罪亦难逭。", "bai": "", "page": 2588}, {"type": "heading", "wen": "督责知府伍文定等同心剿贼牌", "bai": "", "page": 2589}, {"type": "meta", "wen": "七月二十五日", "bai": "", "page": 2589}, {"type": "para", "wen": "切照天下之事，成于同而败于异。本院选调吉安、赣州、临江、袁州等府、卫、所军民兵快，委各该文武等官知府伍文定、邢珣等统领，分立哨分，授以方略，令其并力进剿，互相策应。今访得各官各持己见，自为异同，累有事机可乘，坐视辄致违错，本当拿究，治以军法，但以用人之际，姑且容恕。及照逆贼归援声息已逼，虑恐各官仍蹈覆辙，临期或致偾事，拟合申饬通行。为此牌仰本官，即便督率原领军兵，在于见驻札处所，务要遵依方略，与各哨领兵官同心而行，誓竭并力进死之志，毋为观望苟生之谋。敢有仍前人怀一心，互有异同，以致误事，定行罪坐所由，断依军法斩首，的不食言。先具不致异同重甘结状，并不违依准，随牌缴来。", "bai": "", "page": 2589}, {"type": "heading", "wen": "行南昌府清查占夺民产", "bai": "", "page": 2591}, {"type": "meta", "wen": "八月十六日", "bai": "", "page": 2591}, {"type": "para", "wen": "照得宁王自正德二年以来，图为不轨，诛求财货，强占田土池塘屋基，立表所至，敢怒而不敢言。税粮在户，而租利尽入王府；家眷在室，而房屋已属他人；流移困苦，无所赴诉。见今天厌其虐，自速灭亡，一应侵占等项，合行改正，以苏民困。为此案仰南昌府，即便清查宁王并内官校尉倚势强占，不问省城内外，查系黄册军民，该载税粮明白，即与清复管业，收租住坐，不许邻佑佃民仍前倚势争夺。其曾经奏请如阳春书院等处，虽有侵占，难以擅动，俟另行处治外，仍行官吏务要尽心清查，以副委用，毋得偏私执拗，致生弊端，通毋违错。", "bai": "", "page": 2591}, {"type": "heading", "wen": "批江西按察司优恤孙许死事八月二十五日", "bai": "", "page": 2592}, {"type": "para", "wen": "据按察司呈“副使许逵家眷，日食久缺，并孙都御史未曾殡殓”等情。参看得各官被贼杀害，委可矜怜，合于本司库内各支银三十两，以礼殡殓，候装回日，盘费水手，另行呈夺。许副使家眷缺食，亦听支银五十两，给付应用。取具各该领状，并殡殓过由，同批呈缴。", "bai": "", "page": 2592}, {"type": "heading", "wen": "行南昌府礼送孙公归榇牌", "bai": "", "page": 2593}, {"type": "heading", "wen": "八月二十九日", "bai": "", "page": 2593}, {"type": "para", "wen": "照得江西巡抚都御史孙燧被宁贼杀害，续该本院统兵攻复省城，当给银两买棺装殓间。随据伊男孙庆，带领家人前来扶柩还乡，所据护送人员，拟合行委。为此牌仰府官吏，即于见在府卫官内，定委一员，送至原籍浙江绍兴府余姚县河下交割，并行沿途经过军卫、有司、驿递、巡司等衙门，各拨人夫，程程护送。仍仰照例从厚佥拨长行水手，起关应付，人夫脚力，验口给与行粮，毋得稽迟未便。", "bai": "", "page": 2593}, {"type": "heading", "wen": "讨叛敕旨通行各属", "bai": "", "page": 2594}, {"type": "meta", "wen": "九月初二日", "bai": "", "page": 2594}, {"type": "para", "wen": "节该钦奉圣旨敕：“近该南京内外守备参赞等官，太监黄伟等先后奏报，江西宁王杀害巡抚等官，烧毁府县，肆行反逆等项事情，已下兵部会官议处停当，朕当亲率六师，奉天征讨。先差安边伯朱泰为前哨，统领各边官军前去南京，相机剿杀。太监张忠、左都督朱晖，统领各边官军前去江西，捣其巢穴。又命南和伯方寿祥及南直隶、江西、湖广各该镇巡等官，各照拟定要路，驻扎把截。今特命尔照依该部会奏事理，会同镇守太监王宏，选调堪用官军民快，亲自督领，在于所属紧要地方，分布防御。仍委浙江布政司左布政闵楷，选募处州民快，定拟驻扎地方，听候调用。军中事务，俱要互相传报，彼此通知，一遇有警，勿误策应，或就会合各路人马，设法剿捕。仍出给榜文告示，遍发江西及各该地方张挂晓谕：但有能聚集义兵，擒杀反逆贼犯者，量其功绩大小，封拜侯伯，及升授都指挥指挥千百户等官世袭。贼伙内有能自相擒斩首官者，与免本罪，仍量加恩典。不许乘机挟雠，妄杀平人。一应军中事宜，敕内该载未尽者，俱听尔随宜区处。尔为风宪大臣，受兹重托，宜罄竭忠诚，扫除叛贼，尤要详审慎重，计出万全，务俾地方宁靖，军民安堵，以纾朕南顾之忧，庶称委任，钦此。”钦遵，拟合就行，为此仰都、布、按三司照依案验备奉敕内事理，通行所属，一体钦遵施行。", "bai": "", "page": 2594}, {"type": "heading", "wen": "咨南京兵部议处献俘船只", "bai": "", "page": 2596}, {"type": "heading", "wen": "九月初二日", "bai": "", "page": 2596}, {"type": "para", "wen": "照得属者宁王宸濠杀害守臣，举兵谋逆，云云。拟于九月十一日亲自督解赴阙，但应赴解人犯，并护解官兵数多，本地驿递残破，红站座船，俱被虏毁无存，议雇民船，自浙取道而北，须烦兵部于南京济州、江淮二卫马快船内，各拨十只，中途接载，庶克有济。为此移咨，特差千户林节、主簿于旺前去，烦请选拨马快船二十只，点齐撑驾人役，差委的当官员，与差去官预先押至镇江河下，候本职到彼，替换装载而行，实为两便。谅宁藩之叛逆，固天下臣民之所共愤，则今日之献俘于京，以彰天讨，必亦忠臣义士之所共欲，当不吝于烦劳也。仍希先示之！", "bai": "", "page": 2596}, {"type": "heading", "wen": "行江西三司清查被劫府库起运钱粮", "bai": "", "page": 2597}, {"type": "meta", "wen": "九月初四日", "bai": "", "page": 2597}, {"type": "para", "wen": "照得本年六月十四日宁王谋反，尽将江西都、布、按三司及附郭南昌等府、县库，盘检去讫。中间多系各府、州、县解到起运等项钱粮，未经转解，若不严加查考，恐滋侵欺。为此仰抄案回司，即便吊取原行卷簿到官，责令该库官攒并经手人役，从公清查，要见某项原收某府、州、县，解到某色起运钱粮若干；某项原系贮库纸米赃罚金银器物等件各若干，宁王盘检若干，中间有无官吏库役人等，乘机侵骗情弊，即今见在若干；务要通行查明，备造印信手本，火速缴报，以凭查考施行。仍行南昌等府、州、县一体遵照，将起解赴库钱粮查报，俱毋违错。", "bai": "", "page": 2597}, {"type": "heading", "wen": "行江西布按二司看守宁府库藏", "bai": "", "page": 2598}, {"type": "meta", "wen": "九月十一日", "bai": "", "page": 2598}, {"type": "para", "wen": "照得宁府库藏，已经本院督同戴罪三司官员并各府知府公同封识完固，合就委官监督看守。为此仰抄案回司，即行该司掌印官，督同南昌府同知何继周，及南、新二县掌印官，定委老成晓事官二员，分领佥定大户人等，每夜上宿看守东西二库；仍令兵快把守宁府南东西三门，昼夜巡逻，不许移动一草一砖。二司掌印并该道分巡官，不时巡视闸点，毋得视常虚应故事，倘致疏失，责有所归。", "bai": "", "page": 2599}, {"type": "heading", "wen": "委按察使伍文定纪验残孽", "bai": "", "page": 2599}, {"type": "heading", "wen": "九月二十日", "bai": "", "page": 2599}, {"type": "para", "wen": "照得节该钦奉敕谕：“但有生擒盗贼，鞫审明白，亦听就行斩首示众。贼级行令各该兵备守巡官，即时纪验明白，备行江西按察司，造册奏缴，查照事例，升赏激劝，钦此。”钦遵。为照宁王谋反，随本院调兵，已将宁王俘执，谋党李士实、刘养正、王春等，并贼首凌十一、闵念四等，亦就擒获。即今见该本院不日亲自督解赴阙，式昭圣武，及纪功御史谢源、伍希儒亦各赴京复命。所有各哨官兵，尚在搜剿残孽，惟恐解报前来，不无缺官纪录。为此仰抄案回司，即行新任按察使伍文定，如遇各哨官兵解到叛贼并赃仗等项，务要从实审验，应处决者，照依本院敕谕事理，就行斩首，贼级枭挂，明白纪录，备造印钤文册，差人径自奏缴。仍造清册一本，缴报本院查考，毋得违错不便。", "bai": "", "page": 2600}, {"type": "heading", "wen": "委知府伍文定邢珣防守省城牌", "bai": "", "page": 2601}, {"type": "meta", "wen": "九月十二日", "bai": "", "page": 2601}, {"type": "para", "wen": "照得江西大乱剿平，地方幸已稍靖。但巡抚官员被杀，巡按及三司府、州、县、卫、所等官，俱各戴罪听参，本院即今又督官兵押解宁王并其党与赴京。省城居民，久遭荼苦，疮痍未起，惊疑未息，虽经抚谕，诚恐本院去后或有意外之虞，拟合委官留兵防守。为此牌仰领兵知府伍文定、邢珣等，即便照依后开班次，轮流各行量带官兵，昼夜固守城池，保障地方，抚安居民，禁革骚扰。候抚按官员及三司等官到任事定之日，方许回还，照旧管事。毋得违错。", "bai": "", "page": 2601}, {"type": "para", "wen": "计开：", "bai": "", "page": 2602}, {"type": "heading", "wen": "一班知府伍文定、邢珣。二班徐琏、戴德孺。", "bai": "", "page": 2602}, {"type": "para", "wen": "三班曾玙。四班周朝佐、林珹。", "bai": "", "page": 2602}, {"type": "heading", "wen": "行江西布按二司厘革抚绥条件", "bai": "", "page": 2602}, {"type": "meta", "wen": "九月十二日", "bai": "", "page": 2602}, {"type": "para", "wen": "照得江西未乱之前，民伪颇滋，吏政多弊，抚治之责，已号烦难。况大乱之后，钱粮有侵克之费，军伍有缺乏之虞；奸恶伪兴，灾旱荐作；法度申明之未至，官吏怠玩之或生；本院讨贼平乱，功虽告成；厘革抚绥，力尚未遍；若不条析处分，深为未便。为此仰抄案回司，照依案验内事理，逐一遵照施行。务使事各举行，民沾实惠，毋得虚应故事，取罪不便。", "bai": "", "page": 2602}, {"type": "para", "wen": "计开：", "bai": "", "page": 2603}, {"type": "para", "wen": "一，省城大乱，固已剿平，地方守备，难便废弛。除南、新二县机兵令分巡该道分拨守门外，仰布、按二司掌印官，会同于所属邻近府州，酌量原编机兵多寡，量取辏二千名，各委相应人员，带领来省操练，以备不虞。仍行南昌道分巡官较视点闸。其各兵口粮，就令各该县分动支预备仓米谷，计日分给，候事完之日停止。", "bai": "", "page": 2603}, {"type": "para", "wen": "一，十四年起运兑淮，间有被贼虏掠。其未兑及未到水次并偏僻去处未经贼掠者尚多，诚恐官吏粮里人等，乘机隐匿，捏故侵欺。合先行查，仰布、按二司掌印官，即行各该府、州、县，将已兑粮数通查，要见见在若干，果被贼虏若干，取具重甘结状，造册缴报，以凭议处。其见在粮米，就于所在地方暂且囤贮看守。如有未兑捏作已兑，不曾被贼捏作贼劫者，照例问发充军，官吏坐拟赃罪不恕。", "bai": "", "page": 2604}, {"type": "para", "wen": "一，南昌、九江、南康三府被贼残害，尤宜矜恤。仰布、按二司掌印官，作急查勘呈来，以凭议处。", "bai": "", "page": 2604}, {"type": "para", "wen": "一，南昌左卫旗军，多因从逆擒斩，以致缺伍。仰布、按二司官即便出给告示，许令在逃旗军并余丁投首，照依榜例，免其罪名，著令顶补军役，暂委官员管领，以备操守。", "bai": "", "page": 2605}, {"type": "para", "wen": "一，建昌、安义二县贼首，虽已擒获，遗漏余党尚多，今既奉有榜例，合与更新。仰布、按二司转行该县出给告示，许各自新，痛改前恶，即为良民，有司照常抚恤，团保粮里，不得挟私陷害。如有不悛，仍旧为非者，擒捕施行。", "bai": "", "page": 2605}, {"type": "para", "wen": "一，宁王庄田基屋湖地，并宁府官员人役，及投入用事从逆等项人犯田产，例应籍没，合先查理。除将内官黄瑞基屋改作东湖书院，以便学者讲习外，其余仰布、按二司掌印官，会同南昌道分巡官行委的当官员，逐一清查，如田庄要见坐落地名何处，田亩若干，山场树木若干，湖地广阔若干，房屋几间。今年见在花利，即便收贮所在地方，责人看守，通造手册缴报。其有原系占夺民间物业，相应给还，及估价发卖仍佃者，俱候查明之日，从容呈议审处。敢有隐匿，及指以原业捏称借贷，辄行据占者，先行拿问不恕。", "bai": "", "page": 2605}, {"type": "para", "wen": "一，省城各衙门并公廨，有残圮应合修理者，仰布、按二司掌印官会同该道官，参酌缓急，行令府县，移拆无用房屋，量加修理，毋得虚费财物。", "bai": "", "page": 2606}, {"type": "para", "wen": "一，省城湖地，仰布、按二司行南昌府县：其城濠，行都司，各委人看守。鱼利公同变收入官，以备公用，不许私取及致人偷盗。", "bai": "", "page": 2606}, {"type": "para", "wen": "一，今年乡试，因乱废格，除应否补试，另行议奏外，其未乱之前，已经举行未毕事件，合先查究。仰布政司将原发修理贡院席舍，并发买物料等项银两若干，委何人管，即今已修完，并已买到物料若干，见存银两若干，查明造报，毋得因循，致令吏胥乘机隐匿作弊。其已买物料，有不堪贮者，姑令变价还官，以俟再买。以后未举事件，有应合预处者，会同按察司并该道官，一面议处施行。按察司仍行提学官，转行所属知悉。", "bai": "", "page": 2607}, {"type": "heading", "wen": "行江西按察司知会逆党宫眷姓名", "bai": "", "page": 2607}, {"type": "para", "wen": "仰抄案回司，着落当该官吏，即便查照施行。仍呈钦差提督军务御马监太监张，钦差提督军务充总兵官安边伯朱知会，俱毋违错。", "bai": "", "page": 2608}, {"type": "para", "wen": "计开：宁王郡王将军世子共十六名。", "bai": "", "page": 2608}, {"type": "heading", "wen": "见在十四名：宸濠拱栟觐铤拱樤宸洧宸瀛觐樤宸汲宸汤宸沨宸浐宸澜大世子一哥", "bai": "", "page": 2608}, {"type": "heading", "wen": "已故二名：拱槭二世子二哥", "bai": "", "page": 2608}, {"type": "para", "wen": "谋党重犯六十七名：", "bai": "", "page": 2608}, {"type": "heading", "wen": "见在五十九名：刘吉涂钦乐平黄瑞傅明陈贤尹秀梁伟", "bai": "", "page": 2608}, {"type": "heading", "wen": "沈鏊熊绶周瑞吴松张嵩李蕃于全秦荣", "bai": "", "page": 2609}, {"type": "meta", "wen": "萧奇徐辂贺俊李琳丁璝王储甘桂王琪", "bai": "", "page": 2609}, {"type": "heading", "wen": "杨昇张隆刘勋葛江杨允徐锐丁纲夏振", "bai": "", "page": 2609}, {"type": "heading", "wen": "唐玉何受朱煜冯旻周勇周鼎於琦张凤", "bai": "", "page": 2609}, {"type": "heading", "wen": "袁贵闻凤顾正顾雄徐纪倪六王凤唐全", "bai": "", "page": 2609}, {"type": "heading", "wen": "闵念八李世英徐淦凤张宣闵念四凌十一", "bai": "", "page": 2609}, {"type": "heading", "wen": "万贤一朱会价万贤二熊十四熊十七", "bai": "", "page": 2609}, {"type": "heading", "wen": "已故八名：万锐陆程刘养正余祥甘楷王信卢铺刘子达", "bai": "", "page": 2610}, {"type": "heading", "wen": "宫眷四十三口：赵氏万氏钟氏徐氏宣氏张氏张氏陆氏", "bai": "", "page": 2610}, {"type": "heading", "wen": "蒋氏陆氏赵氏王氏王氏李氏朱氏郑氏", "bai": "", "page": 2610}, {"type": "heading", "wen": "陈氏徐氏刘氏何氏张氏祥瑞王氏锦英", "bai": "", "page": 2610}, {"type": "heading", "wen": "王氏徐氏周氏周氏桂祥陈氏春受刘氏", "bai": "", "page": 2610}, {"type": "heading", "wen": "顾氏陈氏婆氏王氏艾儿碧云刘氏串香", "bai": "", "page": 2610}, {"type": "heading", "wen": "异兰爱莲彭氏", "bai": "", "page": 2611}, {"type": "heading", "wen": "小火者二口：乐秋乐萱", "bai": "", "page": 2611}, {"type": "para", "wen": "马八区。金册十二副，计二十四叶。", "bai": "", "page": 2611}, {"type": "heading", "wen": "行江西按察司编审九姓渔户牌", "bai": "", "page": 2611}, {"type": "meta", "wen": "九月二十四日", "bai": "", "page": 2611}, {"type": "para", "wen": "为照贼首吴十三、凌十一、闵念四、念八等，俱已擒获，党类亦多诛剿；虽有胁从之徒，皆非得已，节该本院备奉钦降黄榜，通行给发晓谕，许其自首，改过自新，安插讫。数内杨子桥等九姓渔户，又该知县王轼引赴军门投首，审各执称被胁，情有可矜，当该本院量行责治，仍发本官带回安抚外。今访得前项渔户，尚有隐匿未报及已报在官而乘势为非者；况查沿江湖港等处，亦有渔户，以打鱼为由，因而劫杀人财；虽尝缉捕禁约，而官吏因循，禁防废弛，合就通行查处。为此仰抄案回司，即便选委能干官员，会同安义等县掌印、捕盗等官，拘集杨子桥等九姓渔户到官，从公查审，要见户计若干，丁计若干，已报在官若干，未报在官若干，各驾大小渔船若干，原在某处地方打鱼生理，著定年貌籍贯，编成牌甲，每十名为一牌，内佥众所畏服一名为小甲；地方多寡，每五牌或六牌为一甲，内佥众所信服一名为总甲，责令不时管束戒谕。仍于原驾船梢，粉饰方尺，官为开写姓名、年甲、籍贯、住址，及注定打鱼所在，用铁打字号，火烙印记，开造印信手册在官，每月朔望各具不致为非结状，亲自赴县投递，用凭稽考点闸。中间如有隐匿不报者，俱许投首免罪，亦就照前行。若有已报在官，仍前乘机为非，抗顽不行到官，就仰从长计议，应抚应捕，遵照本院钦奉敕谕随宜处置事理，径自施行。今后但有上户官民客商人等被害，就于本处追究，务在得获，明正典刑。仍即通行南昌等一十三府及各州、县一体查处，编立牌甲，严加禁约施行，造册缴报查考。如或故违，定将首领官吏拿问，决不轻贷。", "bai": "", "page": 2611}, {"type": "heading", "wen": "献俘揭贴", "bai": "", "page": 2613}, {"type": "meta", "wen": "九月二十六日", "bai": "", "page": 2613}, {"type": "para", "wen": "准钦差提督赞画机密军务御用监太监张揭帖开称，今照圣驾亲率六师，奉天征讨，已临山东、南直隶境界，所据前项人犯，宜合比常加谨防守调摄，待候驾临江西省下之日，查勘起谋根由明白，应否起解斩首枭挂等项，就彼处分定夺。若不再行移文知会，诚恐地方官员不知事理，不行奏请明旨，挪移他处，或擅自起解，致使临难对证，有误事机，难以悔罪等因，准此。卷查先为飞报地方谋反重情事云云。本职已将宁王并逆党，亲自量带官兵，径从水路，照依原拟日期，启行解赴京师，已至广信地方外。今又准前因，及该差官留本职并宁王及各党类回省。为照前项人犯，先监按察司，责委官员人等，昼夜严加关防；有病随即拨医调治，数内谋党李士实、王春、刘养正等，已多医治不痊，俱各身故。随差官吏仵作人等前去相验，责付浅殡，拨人看守。其宁王及谋党刘吉等，俱系恶焰久张之人，设若淹禁不行解报，纵有官兵加谨防守，恐或扇诱别生他奸。今若留回省城，中途疏虞，尤为可虑。兼且人犯多生疟痢，沿途亦即拨医调治。又有数内镇国将军拱槭并世子二哥，各行身故；又经差官相明，买棺装殓，责仰贵溪县拨人看守。其余尚未痊可，若更往返跋涉，未免各犯性命愈加狼狈，相继死亡，终无解京人犯，抑恐惊摇远近，变起不测。本职亲解宁王，先已奏闻朝廷，定有起程日期，岂敢久滞因循，不即解献，违慢疏虞，罪将焉逭？及照库藏册籍等项，未准揭帖之先，已会多官封贮在库，待命定夺。况新任按察使伍文定，及戴罪三司官、领兵知府等官，俱各见在，封识明白，别无可疑。除将宁王宸濠等，各另差官分押；宫眷妇女，行各将军府取有内使管伴，俱照旧亲自解京外，所有库藏等项，奉有明旨，自应查盘起解，就请公同三司并各府等官，眼同径自区处，为此合用揭帖前去，烦请查照施行。", "bai": "", "page": 2614}, {"type": "heading", "wen": "行袁州等府查处军中备用钱粮牌", "bai": "", "page": 2616}, {"type": "meta", "wen": "十月初六日", "bai": "", "page": 2616}, {"type": "para", "wen": "据吉安府申“奉本院钧牌，查得本府在库止有赃罚纸米银一万五千四百三十一两零，其各县寄库银四万六千一百五十九两零，俱系转解之数，似难支动。见今动调各处军快人等数多，诚恐支用不敷，及查庐陵等九县贮库钱粮，亦多称乏，合行邻近府分帮助支用”缘由到院。为照江西宁府变乱，虽经本院起调广东、福建二省汉土狼达官军，江西南、赣等处兵快，计有二十余万，合用粮饷大约且计三四月之费。今该府所申，堪支纸米等银止有一万五千四百有零，其余俱系解京之数，就便从权支用，亦有未敷，必须于各府、县见贮钱粮数内查支接济，庶不误事，拟合通行。为此牌仰本府，即将收贮在库不拘何项钱粮，作急通行查出，三分为率，内将二分称封明白，就委相应官员，不分雨夜，领解军门，以凭接支应用。此系征讨叛逆军机重务，毋得稽迟时刻，定以军法论处，决不轻贷。", "bai": "", "page": 2616}, {"type": "heading", "wen": "行江西布按二司清查军前取用钱粮", "bai": "", "page": 2618}, {"type": "para", "wen": "案照先因宁王变乱，该本部备行南、赣等府，起调各项军兵追剿，合用粮饷等项，就仰听将在官钱粮支给间。随据吉安府申称，动调兵快数万，本府钱粮数少，乞为急处等情。已经通行各府，速将见贮不拘何项钱粮，以三分为率，内将二分解赴军前接济外。", "bai": "", "page": 2618}, {"type": "para", "wen": "续看前项事情，系国家大难，存亡所关，诚恐兵力不敷。又牌行各该官司，即选父子乡兵，在官操练，听将官钱支作口粮，候本院另有明文一至，启行去后。", "bai": "", "page": 2618}, {"type": "para", "wen": "今照前项首恶并其谋党，俱已擒斩，原调各处军兵，久已散归，所据用过粮饷等项，合行查造。为此仰抄案回司，即查各府、州、县自用兵日起，至掣兵日止，要见某项钱粮，差何人役解赴军前，应用若干，有无获奉批回在卷；又将某项钱粮，差何人役解赴某官处，支给官兵口粮等项若干，自某月日期起，至某月日止，各支若干；或系那借，惟复措置之数，务要清查明白，类造文册，星驰差人送院查考。中间如有官吏人等通同作弊，重支冒领；或以少作多，侵欺捏报者，就便拿问，照例发遣，毋得违错。", "bai": "", "page": 2619}, {"type": "heading", "wen": "防制省城奸恶牌", "bai": "", "page": 2619}, {"type": "meta", "wen": "十二月十一日", "bai": "", "page": 2619}, {"type": "para", "wen": "照得江西省城，近遭宁王之变，巡逻无官，非但军门凋敝，禁防疏阔；兼又军马充斥街巷，难辨真伪；有等无籍小民，因而售奸为恶，恐致日久酿成大患，必须预防早戒，庶使地方有赖。", "bai": "", "page": 2620}, {"type": "para", "wen": "查得江西都司都指挥马骥，素有干材，军民畏服，合就行委。为此牌仰抄案回司，即行本官，不妨原任，严督府、卫、所、县军民兵快，并地方总小甲人等，于省城内外昼夜巡逻。固守城池，保障地方，洁静街道，禁缉喧争。但有盗贼，即便设法擒捕，务在得获解官问招呈详，不许妄拿平人，攀诬无干良善，及纵令积年刁徒，吓诈财物，扰害无辜。仍要严加省谕远近乡村居民，各安生理，毋得非为，及容隐面生可疑之人在家，通诱贼情，坐地分赃。敢有故违，仰即拿赴军门，治以军法。承委官员，务在地方为事，用心管要，以称委用，不得因循怠忽，取究未便。", "bai": "", "page": 2620}, {"type": "heading", "wen": "行江西按察司查禁因公科索民财", "bai": "", "page": 2621}, {"type": "meta", "wen": "十二月十一日", "bai": "", "page": 2621}, {"type": "para", "wen": "照得圣驾南征，所有供应军马粮草并合用器皿等项，已该江西布、按二司分派各府、州、县支给在库官钱，均派经过府、县应用。近访得各该官吏，多有不遵法度，或将官库钱粮，通同侵欺入己，乘机科派民间出办；或取金银器皿银两，或要牛马猪羊等物，辄差多人下乡，狐假虎威，扰害殆遍。中间积年刁徒，又行百般需索，稍有不遂，辄称殴打抗拒，耸信官府，添人捉拿，加以刑辱，重行追索。若不查禁处置，深为民患。为此仰抄案回司，即便会同布政司掌印官，速行计处，先将各应支银两，查解应用；若有不足，就将在库不拘何项银两，给支接济。俱要造册开报，以凭查考，事毕之日，再行议处，作正支销，或设法追补。其各府、州、县科取民间财物，即行查究禁革，未到官者，毋再追并；已在官者，照数给还。中间敢有隐瞒纤毫不发，体访得出，或被人首告，定行拿问赃罪，决不轻贷。仍先出给告示，发仰所属张挂晓谕，务使知悉，俱毋违错。", "bai": "", "page": 2621}, {"type": "heading", "wen": "禁省词讼告谕", "bai": "", "page": 2623}, {"type": "meta", "wen": "十二月十七日", "bai": "", "page": 2623}, {"type": "para", "wen": "近据南昌等府、州、县人等诉告各项情词到院，看得中间多系户婚田土等事，虽有一二地方重情，又多繁琐牵扯，不干己事，在状除情可矜疑者，亦量轻重准理，其余不行外。为照江西地方，近因宁王变乱，比来官军见省城空虚，况闻圣驾将临，有司官员，俱各公占委用，分理不暇；远近居民，又有差役答应，奔走无休；本院志在抚安地方，休息军民，当此多事之时，岂暇受理词讼？必待地方宁靖，兵众既还，官府稍暇，方从容听断。为此合行出给告示，晓谕各府、州、县军民人等，暂且各回生理，保尔家室，毋轻忿争，一应小事，各宜含忍。不得辄兴词讼，不思一朝之忿，锱铢之利，遂致丧身亡家；始谋不臧，后悔何及。中间果有赃官酷吏，豪奸巨贼，虐众殃民，患害激切者，务要简切直言，字多不过一二行，陈告亦须自下而上，毋致蓦越。其余一切事情，俱候地方宁谧，官军班还之日，各赴该管官司告理。若剖断不公，或有亏枉，方许申诉。敢有故违，仍前告扰者，定行痛责，仍照例枷号问发，决不轻贷。", "bai": "", "page": 2623}, {"type": "heading", "wen": "再禁词讼告谕", "bai": "", "page": 2624}, {"type": "meta", "wen": "十二月", "bai": "", "page": 2624}, {"type": "para", "wen": "照得本院屡出告示，晓谕军民人等，令其含忍宁耐，止息争讼。而军民人等，全不体息，纷纷告扰不已。及看所告情词，多系小事忿争，全是繁文牵扯，细字叠书，殊可厌恶。当此多事，日不暇给，词状动以千百，徒费精神，何由遍览。除已前情词，俱已不行外，为此再行晓谕，敢有仍前不遵告谕，故违告扰者，定行照例枷号，从重问发，的不虚示。", "bai": "", "page": 2624}, {"type": "para", "wen": "计开：", "bai": "", "page": 2625}, {"type": "para", "wen": "一，本院系风宪大臣，职当秉持大体，正肃百僚，非琐屑听理词讼之官。今后军民人等，一应户婚、田土、斗争、债负、钱粮、差役等事，俱要自下而上，府、州、县问断不公，方许告守巡按察衙门。守巡按察问断不公，方许赴本院陈告。敢有越诉渎冒宪体者，痛责。", "bai": "", "page": 2625}, {"type": "heading", "wen": "征藩公移下", "bai": "", "page": 2626}, {"type": "heading", "wen": "凡二十七条", "bai": "", "page": 2626}, {"type": "heading", "wen": "开报征藩功次赃仗咨", "bai": "", "page": 2626}, {"type": "meta", "wen": "正德十五年三月初四日", "bai": "", "page": 2626}, {"type": "para", "wen": "准钦差整理兵马粮草等项兵部左待郎兼都察院左佥都御史王咨，内开“烦为查照，将征剿防守有功官军人等，俱照功次，分别明白，造册咨送，以凭查议”等因。", "bai": "", "page": 2626}, {"type": "para", "wen": "卷查先为飞报地方谋叛重情事，本职奉命前往福建公干，中途遭遇宁府反叛，谋危宗祀，系国家大难，义不容舍之而往。当即保吉安，随具本奏闻，及星夜行文各府，起调兵快，招募四方报效义勇。适遇巡按两广御史谢源、伍希儒回京复命，又行具本奏留军前，协谋行事，各哨官兵，俱听监督，获有功次，俱凭本职送发各官审验纪录去后。续督官兵，前后攻复省城，俘执宸濠，并其党与剧贼起解间，随准南京兵部咨开称前事云云。", "bai": "", "page": 2626}, {"type": "para", "wen": "照得江西逆贼，既已擒获。逆党已经剪平，所获功次，合行纪验。除原差科道官前来外，烦将征剿逆贼官军民兵，招募义勇，及乡官人等所获功次，分别奇功、头功、次功，造册覆验等因，案经备行江西按察司查照施行去后。", "bai": "", "page": 2627}, {"type": "para", "wen": "今准前因，看得征剿宸濠之时，止是分布哨道，设伏运谋，以攻城破敌为重，擒斩贼徒为轻；且攻城破敌，虽系本职督领各哨官兵协谋并力，缘任非一人，事非一日，各官俱系同功一体，难以分别等第。其擒斩贼徒，虽有等级，自有下手兵夫，难以加于各官之上。止将各哨擒斩贼犯送发御史谢源、伍希儒审验明白，从实直纪；缘各官不曾奉有纪功之命，但照本职钦奉敕谕便宜事理，从权审验纪录，难以分别奇功、头功、次功等项名目。止于造册内开写某人擒斩某贼首、某贼从；重轻多寡，据实造册，中间等第，亦自可见。除行各官再行查照造册径缴外，所据擒获功次总数，及官军兵快报效人等员名数目，合行开造咨报施行。", "bai": "", "page": 2628}, {"type": "para", "wen": "计开：", "bai": "", "page": 2628}, {"type": "para", "wen": "一，提督领兵官一员：", "bai": "", "page": 2629}, {"type": "heading", "wen": "钦差提督南、赣、汀、漳等处军务都察院右副都御史王。", "bai": "", "page": 2629}, {"type": "para", "wen": "一，协谋讨贼审验功次官二员：", "bai": "", "page": 2629}, {"type": "para", "wen": "钦差巡按两广监察御史谢源、伍希儒。", "bai": "", "page": 2629}, {"type": "para", "wen": "一，领哨官十员：", "bai": "", "page": 2629}, {"type": "para", "wen": "冲锋破敌：", "bai": "", "page": 2629}, {"type": "heading", "wen": "吉安府知府伍文定、赣州府知府邢珣、袁州府知府徐琏、临江府知府戴德孺。", "bai": "", "page": 2629}, {"type": "para", "wen": "邀伏截杀：", "bai": "", "page": 2629}, {"type": "para", "wen": "赣州卫署都指挥佥事余恩、抚州府知府陈槐、建昌府知府曾玙、饶州府知府林珹、广信府知府周朝佐、瑞州府通判胡尧元。", "bai": "", "page": 2629}, {"type": "para", "wen": "一，分哨官十一员：", "bai": "", "page": 2630}, {"type": "para", "wen": "邀伏截杀：", "bai": "", "page": 2630}, {"type": "para", "wen": "吉安府泰和县知县李楫、临江府新淦县知县李美、吉安府万安县知县王冕、南康府安义县知县王轼、瑞州府通判童琦。", "bai": "", "page": 2630}, {"type": "para", "wen": "守把截杀：", "bai": "", "page": 2630}, {"type": "para", "wen": "吉安府通判谈储、吉安府推官王暐、南昌府进贤县知县刘源清、南昌府奉新县知县刘守绪、南昌府推官徐文英、抚州府临川县知县傅南乔。", "bai": "", "page": 2630}, {"type": "para", "wen": "一，随哨官四十六员：", "bai": "", "page": 2630}, {"type": "para", "wen": "邀伏截杀：", "bai": "", "page": 2631}, {"type": "para", "wen": "吉安府通判杨昉、吉安守御千户所指挥同知麻玺、赣州府同知夏克义、赣州卫指挥佥事孟俊、永新守御千户所指挥同知高睿、南昌府通判陈旦、南昌府丰城县知县顾佖、袁州府推官陈辂、南昌府宁州知州汪宪、饶州府余干县知县马津、瑞州府上高县知县张淮、瑞州府高安县知县应恩、吉安府永新县知县柯相、南昌府建昌县知县方泽、南昌府靖安县知县万士贤。", "bai": "", "page": 2631}, {"type": "para", "wen": "守把截杀：", "bai": "", "page": 2631}, {"type": "para", "wen": "广信府沿山县知县杜民表、广信府永丰县知县谭缙、瑞州府同知杨臣、瑞州府新昌县知县王廷、饶州府安仁县知县杨材、广信府通判俞良贵、广信府通判安节、广信府推官严铠、临江府同知奚钺、临江府通判张郁、广信府同知桂鏊、瑞州府推官金鼎、赣州府赣县知县宋瑢、赣州卫正千户刘镗、赣州卫正千户杨基、广信守御千户所千户秦逊、永新县儒学训导艾珪、瑞州府高安县县丞卢孔光、饶州府余干县县丞梅霖、南昌府靖安县县丞彭龄、吉安府万安县县丞李通、南昌府武宁县县丞张翱、赣州府兴国县主簿于旺、瑞州府高安县主簿胡鉴、饶州府余干县龙津驿驿丞孙天裕、南昌府南昌县市义驿驿丞陈文瑞、吉安府吉水县致仕县丞龙光、赣州府赣县选官雷济、南昌府丰城县省察官文栋材、赣州府赣县义官萧庾、南安府上犹县义官尹志爵。", "bai": "", "page": 2631}, {"type": "para", "wen": "一，协谋讨贼乡官十二员：", "bai": "", "page": 2632}, {"type": "para", "wen": "致仕都御史王懋中、养病痊可编修邹守益、丁忧御史张鳌山、养病郎中曾直、养病评事罗侨、调用佥事刘蓝，致仕按察使刘逊、致仕参政黄绣、闲住知府刘昭、依亲进士郭持平、参谋驿丞王思、参谋驿丞李中。", "bai": "", "page": 2633}, {"type": "para", "wen": "一，戴罪杀贼官一十七员：", "bai": "", "page": 2633}, {"type": "para", "wen": "九江兵备副使曹雷、九江府知府汪颖、九江府德化县知县何士凤、九江府彭泽县知县潘琨、九江府湖口县知县章玄梅、南康府知府陈霖、南康府同知张禄、南康府通判蔡让、南康府通判俞椿、南康府推官王诩、南康府星子县主簿杨永禄、南康府星子县典史叶昌、南昌府知府郑、南昌府同知何继周、南昌府通判张元澄、南昌府南昌县知县陈大道、南昌府新建县知县郑公奇。", "bai": "", "page": 2633}, {"type": "heading", "wen": "一，提调各哨官军兵快人等，除分布把守外，临阵共一万四千二百四十三员名。", "bai": "", "page": 2634}, {"type": "para", "wen": "一，擒斩首从贼人贼级，并俘获宫人贼属，夺回被胁被虏，招抚畏服官民男妇等项，共一万一千五百九十六名颗口；生擒六千二百七十九名：首贼一百零四名，从贼六千一百七十五名，内审放一千一百九十二名；斩获贼级四千四百五十九颗；俘获宫人四十三名，贼属男妇二百三十八名口；夺回被胁被虏官民人等三百八十四员名口；招抚畏服投首一百九十三位名。", "bai": "", "page": 2634}, {"type": "para", "wen": "一，夺获诰命、符验，并各衙门印信关防，金银赃仗等物：诰命一道，符验一道，印信关防一百零六颗，金并首饰六百二十三两一钱二分，银首饰、器皿八万三千八百九十七两一钱五分八厘五毫，赃仗一千八百九十件，器械一千一百九十九件，牛三十头，马一百零八匹，驴骡一十三头，鹿三只。", "bai": "", "page": 2634}, {"type": "para", "wen": "一，追获金玺二颗，金册二付。", "bai": "", "page": 2635}, {"type": "para", "wen": "一，烧毁贼船七百四十六只。", "bai": "", "page": 2635}, {"type": "para", "wen": "一，阵亡兵六十八名。", "bai": "", "page": 2635}, {"type": "heading", "wen": "进缴征藩钧帖", "bai": "", "page": 2635}, {"type": "meta", "wen": "四月十七日", "bai": "", "page": 2635}, {"type": "para", "wen": "卷查先奉钦差总督军务威武大将军总兵官后军都督府太师镇国公朱钧帖：“节该钦奉制谕：‘江西宸濠悖逆天道，谋为不轨，欲图社稷，得罪祖宗。兹特命尔统率六师，往正其罪，殄除叛逆，以安地方。其随军内外提督及各处镇巡等官，悉听节制。钦此。’钦遵，合行钧帖，仰提督南、赣、汀、漳兼巡抚江西等处右副都御史王守仁，照依制谕内事理，即便转行所属司、府、卫、所、州、县、驿、递衙门，一体钦遵施行”等因，已经依奉备行各属钦遵，及具不违依准，备由呈缴去后。", "bai": "", "page": 2635}, {"type": "para", "wen": "本职遵奉总督军门节制方略，领部下官军，克复南昌府城，擒获叛党宜春王拱樤，及将军仪宾从逆守城人等一千有余。随于鄱阳湖等处连日大战，擒获叛首宁王宸濠，并其谋主李士实、刘养正、王春等，大贼首吴十三、凌十一等，及其党与胁从人等共一万一千有奇。除将擒斩缘由先后具奏外，窃照宸濠谋危宗社，阴蓄异图，十有余年；及其称兵倡乱，远近忧危，海内震动。仰赖总督军门，统领六师，奉天征讨，督率内外提督等官，及运谋设策分布，前来南京、江西等处，相继进剿，故旬月之间，扫平逆党，奠安宗社。此皆总督军门神武英略，奇谋妙算，一振不杀之威，遂收平定之绩；而内外提督等官，协谋赞成，并力效命之所致也。职等仰仗德威，遵奉方略，不过奔走驱逐，少效犬马之劳而已，何功之有？所有原奉钧帖，今已事完，理合进缴。除部下获功官兵人等，备行纪功官径自查审缴报外，缘系十分紧急军情，及奏缴钧帖事理，合行具由呈乞施行。", "bai": "", "page": 2636}, {"type": "heading", "wen": "行江西三司搜剿鄱阳余贼牌五月十一日", "bai": "", "page": 2637}, {"type": "para", "wen": "照得江西鄱阳湖等处盗贼，节行告示晓谕，各安生理，而稔恶不悛者尚多；又有应捕人等，相率同盗；或名虽投首，实阴怀反侧。近因本院驻扎省城月余，节据官民赴告，盗贼纵横，随行巡捕等官，上紧缉捕，未见以时获报。各官平素怠玩，本当参拿究治，姑且记罪。另行所据前贼，若不速剿，未免酿成大患。为此仰抄案回司，即便备行督捕都指挥佥事冯勋，分守该道，分巡该道，密切赍文，分投近湖各府县该司等衙门，著落掌印捕盗等官，各选骁勇机快人等，各备锋利刀、枪、弓箭、火铳等项，雇惯经风浪船只，及能谙水势水手撑驾；查将在库官钱给作口粮；选委胆略官员管领，俱听都指挥佥事冯勋总统约束；分布哨道，多差知因人役，探贼向往，就便刻期剿杀。务限一月之内尽获，无留芽孽遗患。若违限不获，先将各官住俸杀贼，若怠玩两月之外，通行解赴军门，治以军法。其兵快人等，若有违限逗遛，畏缩误事者，就仰总统官于军前查照本院钦奉敕谕事理，量以军法罚治。仍要戒约应捕，不许妄拿平人，及容贼妄攀，吓诈财物，并卖放真盗，滥及无辜。敢有故违，一体治以军法。承委各官，务要慎重行事，不得轻率寡谋，中贼奸计，所获功次，俱仰解赴该道，从实纪录造报，以凭查考功罪，轻重罚赏，如违节制，国典具存，罪不轻贷。其军中未尽机宜，该道径自处置施行。仍一面先督所属府县，查照本院先颁十家牌式，上紧编举，以为弭盗安民之本，俱毋违错。", "bai": "", "page": 2638}, {"type": "heading", "wen": "追剿入湖贼党牌", "bai": "", "page": 2640}, {"type": "meta", "wen": "十五年", "bai": "", "page": 2640}, {"type": "para", "wen": "据南康府通判林宽呈称：“后港逆犯杨本荣等百十余人，掳船逃入鄱阳湖等处，乞行南昌、饶州等府县，及沿湖巡司居民人等截捕。”看得贼既入湖，良善已分，正可乘机合兵捕剿。为此牌仰守巡南昌道，即行点选骁勇军快六七百名，各执备锋利器械，给与口粮一月，就行督捕都指挥佥事冯勋统领，星夜蹑贼向往，用心缉捕，获功人役，一体重赏。如有违令退缩者，遵照钦奉敕谕事理，听以军法从事。本官务要申严纪律，相机而行，毋得退避轻忽，有失机宜，致贼远窜，贻患地方，军法具存，罪亦难逭。", "bai": "", "page": 2640}, {"type": "heading", "wen": "行岭北道清查赣州钱粮牌", "bai": "", "page": 2641}, {"type": "heading", "wen": "十月二十三日", "bai": "", "page": 2641}, {"type": "para", "wen": "照得本院及岭北守巡该道并赣州府、卫、所、县问完批申呈词，囚犯、纸米、工价、赃罚等项，及官厂日逐收到商税银两，俱经该官府追收贮库，以备军饷。年久未经清查，该府官吏更换不常，中间恐有那移、侵渔、隐漏等情。为此仰抄案回道，即便亲诣赣州府库，督同该府官，先将正德十二年二月起至正德十五年九月终止，各项纸米、工价、赃罚、商税等项银两卷簿，逐一清查盘理。要见军前用过若干，即今见在若干，有无侵渔、隐漏若干，及有衣物等项，年久朽坏，相应变贸若干，备查开册，缴报本院查考。如有奸弊，就便拿究追问，具招呈详，毋得故纵未便。", "bai": "", "page": 2641}, {"type": "heading", "wen": "申行十家牌法", "bai": "", "page": 2642}, {"type": "para", "wen": "凡立十家牌，专为止息盗贼；若使每甲各自纠察，甲内之人，不得容留贼盗；右甲如此，左甲复如此，城郭乡村无不如此；以至此县如此，彼县复如此，远近州县无不如此；则盗贼亦何自而生？夫以一甲之人，而各自纠察十家之内，为力甚易。使一甲而容一贼，十甲即容十贼，百甲即容百贼，千甲即容千贼矣。聚贼至于千百，虽起一县之兵而剿除之，为力固已甚难。今有司往往不严十家之法，及至盗贼充斥，却乃兴师动众，欲于某处屯兵，某处截捕，不治其本，而治其末，不为其易，而为其难，皆由平日怠忽因循，未尝思念及此也。自今务令各甲各自纠举，甲内但有平日习为盗贼者，即行捕送官司，明正典刑；其或过恶未稔，尚可教戒者，照依牌谕，报名在官，令其改化自新，官府时加点名省谕，又逐日督令各家，轮流沿门晓谕觉察，如此，则奸伪无所容，而盗贼自可息矣。", "bai": "", "page": 2642}, {"type": "para", "wen": "大抵法立弊生，必须人存政举，若十家牌式，徒尔编置张挂；督劝考较之法，虽或暂行，终归废弛。仰各该县官，务于坊里乡都之内，推选年高有德，众所信服之人，或三四十人，或一二十人，厚其礼貌，特示优崇，使之分投巡访劝谕，深山穷谷必至，教其不能，督其不率，面命耳提，多方化导。或素习顽梗之区，亦可间行乡约，进见之时，咨询民瘼，以通下情，其于邑政，必有裨补。若巡访劝谕著有成效者，县官备礼亲造其庐，重加奖励，如此，庶几教化兴行，风俗可美。后之守令，不知教化为先，徒恃刑驱势迫，由其无爱民之实心。若使果然视民如己子，亦安忍不施教诲劝勉，而辄加棰楚鞭挞？孟子云：“善政不如善教之得民也。”况非善政乎？守令之有志于爱民者，其盍思之！", "bai": "", "page": 2643}, {"type": "heading", "wen": "行江西布政司清查没官房产十一月二十日", "bai": "", "page": 2644}, {"type": "para", "wen": "照得逆党没官房屋、田产等项，近经司府出佃与人暂管，候命下之日定夺。近访得官民之家，不论告佃年月先后，地里远近，应否一概混争，若不预为查处，立定规则，将来必致大兴告扰，渐起衅端。为此仰抄案回司，即查前项没官房屋田产，实计若干处所，某月日期经由某衙门与某人，务以年月先后为次，先尽本县人户，然后及于异县；先尽本府人户，然后及于异府。中间多有势豪之徒，不遵则例，妄起争讼，或不由官府，私擅占管占住者，该司通行查出呈来，以凭拿问参究施行，毋得容隐，及查报不清未便。", "bai": "", "page": 2645}, {"type": "heading", "wen": "批再申十家牌法呈", "bai": "", "page": 2646}, {"type": "meta", "wen": "十一月二十九日", "bai": "", "page": 2646}, {"type": "para", "wen": "据江西按察司呈，看得盗贼之纵横，由于有司之玩弛；沿流推本，实如所呈，失事各官，俱合提究，以警将来。但地方多事未完，缺人管理，除该府县掌印官，姑且记罪，责令惩创奋励，修败补隙，务收桑榆之功，以赎东隅之失；其巡捕等官，即行提问，以戒怠弛。仍备行各府县掌印巡捕等官，自兹申戒之后，悉要遵照本院近行十家牌谕，及于各街巷乡村建置锣鼓等项事理，上紧著实举行，严督查考，务鉴前车之覆，预为曲突之徙，毋得仍前玩忽怠弛，但有疏虞，定行从重拿究，断不轻贷，此缴。", "bai": "", "page": 2646}, {"type": "heading", "wen": "批各道巡历地方呈", "bai": "", "page": 2647}, {"type": "meta", "wen": "十一月二十六日", "bai": "", "page": 2647}, {"type": "para", "wen": "据江西按察司呈，看得南昌、湖西、湖东、九江各道地方，兵荒之余，民穷财尽，盗贼蜂起，劫库掠乡，无月无警；府县各官，事无纲纪，申请旁午，文移日繁，政务日废。仰各分巡官，不时往来该道临督所属，设法调度，用其所长，而不责其备；教其不及，而勿挠其权；兴廉激懦，祛弊惩奸，务以息讼弭盗，康宁小民；毋惮一身之劳，终岁逸居省城，坐视民患，藐不经心，俱仰备行各官查照施行。缴。", "bai": "", "page": 2647}, {"type": "heading", "wen": "禁约释罪自新军民告示", "bai": "", "page": 2648}, {"type": "meta", "wen": "正德十六年正月初五日", "bai": "", "page": 2648}, {"type": "para", "wen": "告示：一应平日随从逆府舍余军校人等，论罪俱在必诛，虽经自首，奉有诏宥，据法亦当迁徙边远烟瘴之地，但念其各已诚心悔罪，故今务在委曲安全，仰各洗心涤虑，改恶从善，本分生理，保守身家，毋得仍蹈前非。或又投入各王府及镇守抚按三司等衙门，充作军牢、伴当、皂隶、防夫等项名目，挟持复雠，定行擒拿，追坐从逆重刑。知情容留，官司参究，论以窝藏逆党。同甲邻佑不举首者，连坐以罪。除已奏请外，仰各遵照毋违。", "bai": "", "page": 2648}, {"type": "meta", "wen": "某县某坊第几甲释罪自新一户某人", "bai": "", "page": 2649}, {"type": "heading", "wen": "左邻某人右邻某人", "bai": "", "page": 2649}, {"type": "para", "wen": "仰各邻毋念旧恶，务要与之和睦相处。早晚仍须劝化钤束，毋令投入各府及镇守抚按三司等衙门，充当军牢、伴当、皂隶、防夫等项名目，挟势害人，定行坐以知情容隐逆党重罪，决不轻贷。", "bai": "", "page": 2649}, {"type": "heading", "wen": "批湖广兵备道设县呈", "bai": "", "page": 2649}, {"type": "meta", "wen": "十六年", "bai": "", "page": 2649}, {"type": "para", "wen": "据整饬郴、桂、衡、永等处兵备湖广按察司副使汪玉呈称：“本道接管，看得议奏计处地方以弭盗贼事件，内一件审处贼遗田地，俱经查勘明白：属宜章者，拨与该图领种；属临武者，各归原主；属桂阳者，原议候设立大堰三堡，拨给各堡军兵顶种。续奉巡抚衙门批委同知鲁玘，再行踏勘计处一件，添设屯堡，以严防御。见奉提督衙门案验区处，其第一件设县，所以便抚御，最为紧要重大。县所既设，则更夫有所归著，哨营可以掣散，至于添屯堡、处巡司、并县堡、审田地四事，可以次第兴行。但先因广东守巡兵备等官，所见或异，致蒙该部请命提督大臣亲诣勘处；又缘别有机务，未即临勘，至于今日。本职窃意广东各官，决无不肯协和成事之心，盖因比时多事，未暇细阅文书，及查原经委官，止有同知鲁玘。见在原奉提督衙门行令，径自约会广东各官，速将设县事情及添设屯所事宜查议。除行同知鲁玘前去约会广东该道委官议处，本职仍亲诣适中地方约会外，理合呈详施行”等因到院。卷查先为图议边方后患事，准兵部咨云云。续据湖广按察司呈，奉巡抚湖广都御史秦案验云云。候本院抚临至日，会行议处，具奏定夺施行，各无苟且搪塞去后。", "bai": "", "page": 2650}, {"type": "para", "wen": "今呈前因，参照前项立县等事，关系地方安危，远近人心悬望，恨不一日而成。本院虽奉敕旨，别有机务，不暇亲诣，而该道前任守巡各官，皆有地方重责，自当遵照昼夜经营；却乃因循二年之上，尚未完报，纵使国法可以幸免，不知此心亦何以自安？今照接管副使汪玉，久负体用之学，素有爱民之心，据所呈报，既已深明事机，洞知缓急，遂使举而行之，固当易于反掌，合再督催，以速成绩。为此仰抄案回道，即往彼地约会各该道守巡等官，速将设县等项事情，议处定当，具由呈夺。应施行者，一面施行，务为群策毕举之图，以收一劳永逸之绩。毋再因循，仍蹈前辙未便。仍行都、布、按三司一体查照会议施行。", "bai": "", "page": 2651}, {"type": "heading", "wen": "督剿安义逆贼牌", "bai": "", "page": 2652}, {"type": "meta", "wen": "二月十一日", "bai": "", "page": 2652}, {"type": "para", "wen": "牌仰典史徐诚，既行调选罗坊等处骁勇惯战兵夫四百名，各备锋利器械，就仰该县官于堪动银两内先行给与口粮二月，统领星夜前赴安义县，听凭通判林宽调度追剿，获功人员，一体从重给赏。但有不遵号令及逗遛退缩，扰害平人者，仰即遵照本院钦奉敕谕事理，听以军法从事。本官务要申严纪律，整束行伍，必使所过之地，秋毫无犯；所捕之贼，噍类不遗；庶称委任。如或纵弛怠忽，致有疏虞，军令具存，罪亦难贷。", "bai": "", "page": 2652}, {"type": "heading", "wen": "截剿安义逃贼牌", "bai": "", "page": 2653}, {"type": "meta", "wen": "二月十三日", "bai": "", "page": 2653}, {"type": "para", "wen": "看得安义逆贼，已经本院严督官兵，四路邀截，诚恐无所逃窜，或归冲县治。除行知县熊价，专一防守县治，以守为战；通判林宽，专一追剿逃贼，以战为守；及行都指挥冯勋，选领南昌府卫军快，督兵截剿外，牌仰饶州、南康、九江府掌印官，知府张愈严、王念等，各行起集兵快，身自督领，于沿湖要害，邀截迎击；仍督令余干、乐平、都昌、建昌、湖口、彭泽等县掌印官，领兵把截沿湖紧关隘路江口，毋令此贼得以出境远遁。一面多差知因乡导，探贼向往，互相传报，合势黏踪追剿，一应机宜，俱听从宜区处。各官务要竭力殚智，杀贼立功，以靖地方；毋得畏缩因循，轻忽疏略，至贼滋漫，军法具存，罪难轻贷。", "bai": "", "page": 2653}, {"type": "heading", "wen": "批议赏获功阵亡等次呈", "bai": "", "page": 2654}, {"type": "meta", "wen": "三月初十日", "bai": "", "page": 2654}, {"type": "para", "wen": "据江西按察司呈，看得获功阵亡等员役，俱查照赣州事例，获贼首者，赏银十两；次贼首七两，从贼三两，老弱二两。奋勇对敌阵亡者十两；杀伤死者七两五钱，被伤者三两。其有军民人等，各于贼势未败之先，自行帅众擒获送官者，仍照出给告示，贼首赏二十两，次贼首十两，从贼首五两。务查的实，一例给赏，毋吝小费，致失大信。俱仰行南昌府，于本县支剩军饷银内公同赏功官照数支给，开数缴报查考。", "bai": "", "page": 2655}, {"type": "heading", "wen": "覆应天巡抚派取船只咨", "bai": "", "page": 2655}, {"type": "meta", "wen": "三月二十四日", "bai": "", "page": 2655}, {"type": "para", "wen": "据江西布政司呈：“据应天府呈开：‘江西、九江等府原派船五十只，装运营建宫室物料，乞查处督发，奉批查处呈夺。’议照江西南康、南昌等府，并无马快船只，虽有额造红船，为因宸濠谋反，被贼烧毁；往来使客及粮运，尚且无船装送，疲困已极，委果无从区处。”呈详到院，为照江西各府，师旅饥馑，疲困已极；况兼本职气昏多病，坐视民痍，莫措一筹，前项船只，果难措置。南京素称富庶，今虽亦有供馈之烦，然得贵院抚缉有方，兼以长才区画，何事不济。且江西之疲弊，亦贵院所备知，尝蒙轸念，为之奏蠲租税，江西之民，无不感激。独此数十艘，乃不蒙一为分处乎？为此合咨贵院，烦请查照，悯念疲残之区，终始得惠，别为处拨装运施行。", "bai": "", "page": 2656}, {"type": "heading", "wen": "批东乡叛民投顺状词", "bai": "", "page": 2657}, {"type": "meta", "wen": "四月初九日", "bai": "", "page": 2657}, {"type": "para", "wen": "据东乡县民陈和等连名诉，看得朝廷添设县治，本图以便地方而顺民情，但割小益大，安仁之民既称偏损，亦宜为之处分。在官府自有通融裁制，各民惟宜听顺，果有未当，又可从容告理；而乃辄称背抗，稔恶屡年，愈抚愈甚，不得已而有擒捕之举，亦惟彰国法，禁顽梗，小惩大戒，期在安缉抚定，非必杀为快也。今各民既来投顺，官府岂欲过求，但未审诚伪，恐因擒捕势迫，暂来投顺，以求延缓，亦未可知。仰按察司会同都、布二司，将各情词备加详审，及查立县始末缘由，其各都图，应否归附某县；各县粮差，应否作何区处；各民违抗逃叛之罪，应否作何理断；通行议处呈夺。", "bai": "", "page": 2657}, {"type": "heading", "wen": "批江西布政司清查造册呈", "bai": "", "page": 2658}, {"type": "heading", "wen": "四月十六日", "bai": "", "page": 2658}, {"type": "para", "wen": "据江西布政司呈，看得造册清查之法，既已详悉备具，但人存政举，使奉行不至，则革弊之法，反为流弊之源。仰布政司照议上紧施行，仍备行总理及各守巡官，同以此事为固本安民之首，各至分地，临督各该府、州、县正官。且将别项职事，牒委佐贰官分理，俱要专心致志，身亲棕核，照式依期清量查造，务使积弊顿除，后患永绝，以苏民困。中间但有不行尽心查理，止凭吏胥苟且了事者，即行拿治问发；提调等官，一体参究。其各官分定地方，该司具名开报，缴。", "bai": "", "page": 2658}, {"type": "heading", "wen": "行丰城县督造浅船牌", "bai": "", "page": 2659}, {"type": "meta", "wen": "十六年", "bai": "", "page": 2659}, {"type": "para", "wen": "仰抄案回县，即行知县顾佖速差能干官前来樟树，接驾浅船到县，照依该道估价，于官库支给各船旗军收领。就便择日催督县丞沈廷用，遵照本院面授水帘桅等法，兴工修筑。务将前船衔结勾连，多用串关扇束缚坚牢；足障水势，以便施工，毋为摧荡，虚费财力。", "bai": "", "page": 2659}, {"type": "heading", "wen": "行江西按察司审问通贼罪犯牌", "bai": "", "page": 2660}, {"type": "meta", "wen": "六月十五日", "bai": "", "page": 2660}, {"type": "para", "wen": "照得本院于正德十四年六月内，因宁王谋反，起兵征剿，具本奏闻，当差赣州卫舍人王鼐赍奏，却乃设计诈病，推托不前，显有通贼情弊。及至擒获逆贼，差赍紧关题本，赴京奏报，却又迂道私赴太监张忠处捏报军中事情，几至酿成大变。及将原领题本，通同邀截回还，所据本犯，罪难轻贷。为此牌仰本司，即将发去犯人王鼐从公审问明白，依律议拟，具招呈详。毋得轻从未便。", "bai": "", "page": 2660}, {"type": "heading", "wen": "行江西按察司清查军前解回粮赏等物", "bai": "", "page": 2661}, {"type": "meta", "wen": "六月十九日", "bai": "", "page": 2661}, {"type": "para", "wen": "卷查先该本院督解宸濠，中途奉旨仍解回省，随将前项赏功银牌花红彩段及粮饷等项，牌差县丞等官龙光等，解发江西按察司查收贮库，仍候本院明文施行去后。今照前项粮赏等银，已支未支，清查应该起解者，未审曾否尽数解京，拟合查报。为此牌仰本司，即查原发粮赏等银，各计若干。要见于何年月日奉本院批呈或纸牌，支取某项若干，给与某起官军人等行粮或犒劳兵快应用，其应解金册一十二付，上高、新昌玉印二颗，银盆六面，及衣服等件，曾否尽数解京，中间有无遗漏等情，备查明白，具数回报，以凭查对稽考，毋得迟延未便。", "bai": "", "page": 2661}, {"type": "heading", "wen": "批广东按察司立县呈", "bai": "", "page": 2662}, {"type": "meta", "wen": "七月二十八日", "bai": "", "page": 2662}, {"type": "para", "wen": "据副使汪玉呈称云云。卷查先为图议边方后患事，准兵部咨云云。续据湖广按察司呈，奉湖广巡抚都御史秦案验，候本院抚临至日，会行议处具奏定夺施行。随据副使汪玉呈云云。看得立县之举，今且三年，而两省会议，犹是道傍之谈，似此往复不已，毕竟何时定计。自昔举事，须顺人情；凡今立县，专为弭乱；若使两地人心未协，遂尔执己见而行，则是今日定乱之图，反为异时起争之本，今江西安仁、东乡各县，纷纭奏告，连年不息，即今征矣。除行该道兵备官，上紧约会广东各官，亲诣地方，拘集里老年高有识者，备询舆论；务在众议调停，两情和协，就行相度地势，会计财力，监追起工，然后各自回任。若使议终不合，必欲各自立县，亦须酌裁适均。要见广东于高宿立县，都图若干；湖广于笆篱立县，都图若干；城池高广若干；官员裁减若干；异时赋役，两地逃躲，若何区处；盗贼彼时出没，若何缉捕；一应事宜，逐条开议。须于不同之中，务求通融之术；不得徒事空言，彼此推托，苟延目前，不顾后患，异时追论致祸之因，罪亦终有不免。除批行湖广该道兵备官查照外，仰抄案回司，会同布政司各行该道守巡兵备等官，约会湖广各官，面议停当。一面会计工料，委官及时兴工；一面备由开详，以凭覆奏；毋再推延执拗，致有他虞，断行参究不恕。仍行两广提督并巡按衙门查照催督施行。", "bai": "", "page": 2662}, {"type": "heading", "wen": "行江西三司停止兴作牌", "bai": "", "page": 2664}, {"type": "meta", "wen": "八月初九日", "bai": "", "page": 2664}, {"type": "para", "wen": "先该本院看得江西兵荒之余，重以洪水为灾，民穷财尽，正当体养抚息。各该衙门一应修理公廨工役，俱宜停止。已经案仰各司，即将工役悉行停止，其势不容已者，亦待秋成之后，民困稍苏，方许以次呈夺去后。近因本院出巡，访得各该官员，不思地方兵变水患，小民困苦已极，方求蠲赋税，出内帑欲赈而未能，辄复纷然修理，事属故违。本当参究，但传闻未的，姑再查禁。为此仰各抄案回司，即查前项工程，前此果否悉行停止？近来是否重复兴工？具由呈报，以凭施行，毋得隐讳，违错不便。", "bai": "", "page": 2664}, {"type": "heading", "wen": "行岭北道申明教场军令", "bai": "", "page": 2665}, {"type": "meta", "wen": "九月十七日", "bai": "", "page": 2665}, {"type": "para", "wen": "照得本院调到宁都等县官兵机快人等，见在赣州教场驻扎操阅，中间恐有不守军令，罪及无辜，应合禁约。随据副使王度呈开合行事宜，参酌相同。为此仰抄按回道，即行出给告示，张挂教场，晓谕官兵机快，各加遵守。如有违犯，事情重大者，拿送军门，依军令斩首；其事情稍轻者，该道径自究治发落。仍呈本院查考。", "bai": "", "page": 2666}, {"type": "para", "wen": "计开：", "bai": "", "page": 2666}, {"type": "heading", "wen": "一，各兵但有擅动地方一草一木者，照依军令斩首示众。", "bai": "", "page": 2666}, {"type": "para", "wen": "一，各兵但有管哨官总指称神福，馈送打点等项名色，科派银物自一分以上，俱许赴该道面告究治。", "bai": "", "page": 2666}, {"type": "para", "wen": "一，管哨官凡遇歇操之日，并在营房居住，钤束机兵，教演武艺。敢有在家游荡，及挟妓饮酒，朋伙喧哗者，访出捆打一百。", "bai": "", "page": 2667}, {"type": "para", "wen": "一，各兵但有疾病事故，许管哨官禀明医验，不许雇人顶替，如有用财买求地方光棍替身上操，仰该管总小甲拿获首送该道枷号，如隐情不首，事发，连总小甲一体枷号。", "bai": "", "page": 2667}, {"type": "para", "wen": "一，各兵在市买办柴米酒肉等项，俱要两平交易，如有恃强多占分两，被人告发，枷号示众。", "bai": "", "page": 2667}, {"type": "para", "wen": "一，管哨官凡遇各兵斗殴喧闹等项，小事量行惩治，大事禀该道拿问，不许纵容争竞嚣乱辕门。", "bai": "", "page": 2667}, {"type": "para", "wen": "一，各歇操之日，各将随有器械，务在整刷锋利鲜明，毋得临时有误。如平日懒惰，不行修理，上操之际，弦矢断折，铳炮不响，旗帜不明，查出捆打一百。", "bai": "", "page": 2668}, {"type": "meta", "wen": "一，各兵遇上班之日，不许因便赴该道府告家乡户婚田上等项事情，查出痛责四十。", "bai": "", "page": 2668}, {"type": "para", "wen": "一，各兵上街行走，俱要悬带小木牌一面，上写某哨官总下某人，年甲籍贯辨别。如有隐下兵打名色，另着别样衣冠，暗入府县，挟骗官吏，及来军门并道门首打听消息，访出枷号不恕。", "bai": "", "page": 2668}, {"type": "para", "wen": "一，各兵领到工食银两，俱要撙节用度，谨慎收放，如有奢侈用尽，及被人偷盗，纵来诉告缺失，俱不准理，仍重加责治。", "bai": "", "page": 2668}, {"type": "para", "wen": "一，各该上班兵夫，如有限期未满，先行逃回者，差人原籍拿来，用一百斤大枷枷号教场门首三个月，满日，捆打一百，仍依律问发边远充军。", "bai": "", "page": 2669}, {"type": "para", "wen": "一，各哨官并兵夫，有军门一应便宜，及利所当兴，害所当革者，许赴军门及该道直白条陈，不许诸人阻当。", "bai": "", "page": 2669}, {"type": "heading", "wen": "行雩都县建立社学牌", "bai": "", "page": 2669}, {"type": "meta", "wen": "十二月二十七日", "bai": "", "page": 2669}, {"type": "para", "wen": "照得本院近于赣州府城设立社学乡馆，教育民间子弟，风俗颇渐移易。牌仰雩都县掌印官，即于该县起立社学，选取民间俊秀子弟，备用礼币，敦请学行之士，延为师长；查照本院原定学规，尽心教导；务使人知礼让，户习《诗》、《书》，丕变偷薄之风，以成淳厚之俗。毋得违延忽视，及虚文搪塞取咎。", "bai": "", "page": 2669}, {"type": "heading", "wen": "山东乡试录", "bai": "", "page": 2670}, {"type": "meta", "wen": "弘治甲子前序已刻前卷", "bai": "", "page": 2670}, {"type": "heading", "wen": "四书", "bai": "", "page": 2670}, {"type": "heading", "wen": "所谓大臣者以道事君不可则止", "bai": "", "page": 2671}, {"type": "para", "wen": "负大臣之名，尽大臣之道者也。夫大臣之所以为大臣，正以能尽其道焉耳，不然，何以称其名哉？昔吾夫子因季子然之问以由、求可为大臣，而告之以为大臣之道，未易举也。大臣之名，可轻许乎？彼其居于庙堂之上，而为天子之股肱，处于辅弼之任，而为群僚之表帅者，大臣也。夫所谓大臣也者，岂徒以其崇高贵重，而有异于群臣已乎？岂亦可以奔走承顺，而无异于群臣已乎？必其于事君也，经德不回，而凡所以启其君之善心者，一皆仁义之言，守正不挠，而凡所以格其君之非心者，莫非尧、舜之道，不阿意顺旨，以承君之欲也；必绳愆纠缪，以引君于道也。夫以道事君如此，使其为之君者，于吾仁义之言说而弗绎焉，则是志有不行矣，其可诎身以信道乎？于吾尧、舜之道，从而弗改焉，则是谏有不听矣，其可枉道以徇人乎？殆必奉身而退，以立其节，虽万钟有弗屑也，固将见机而作，以全其守，虽终日有弗能也。是则以道事君，则能不枉其道，不可则止，则能不辱其身，所谓大臣者盖如此，而岂由、求之所能及哉？尝观夫子许由、求二子以为国，则亦大臣之才也；已而于此独不以大臣许之者，岂独以阴折季氏之心？诚以古之大臣，进以礼，退以义，而二子之于季氏，既不能正，又不能去焉，则亦徒有大臣之才而无其节，是以不免为才之所使耳。虽然，比之羁縻于爵禄而不知止者，不既有间矣乎！", "bai": "", "page": 2671}, {"type": "heading", "wen": "齐明盛服非礼不动所以修身也", "bai": "", "page": 2672}, {"type": "para", "wen": "尽持敬之功，端《九经》之本，夫修身为《九经》之本也，使非内外动静之一于敬焉，则身亦何事而修哉？昔吾夫子告哀公之问政，而及于此，若曰：《九经》莫重于修身，修身惟在于主敬；诚使内志静专，而罔有错杂之私，中心明洁，而不以人欲自蔽，则内极其精一矣；冠冕佩玉，而穆然容止之端严，垂绅正笏，而俨然威仪之整肃，则外极其检束矣。又必克己私以复礼，而所行皆中夫节，不但存之静也；遏人欲于方萌，而所由不睽于礼，尤必察之于动也。是则所谓尽持敬之功者如此，而亦何莫而非所以修身哉？诚以不一其内，则无以制其外；不齐其外，则无以养其中；修身之道未备也。静而不存，固无以立其本；动而不察，又无以胜其私，修身之道未尽也。今焉制其精一于内，而极其检束于外，则是内外交养，而身无不修矣。行必以礼，而不戾其所存，动必以正，而不失其所养，则是动静不违，而身无不修矣。是则所谓端《九经》之本者如此，而亦何莫而不本于持敬哉？大抵《九经》之序，以身为本，而圣学之要，以敬为先，能修身以敬，则笃恭而天下平矣。是盖尧、舜之道，夫子举之以告哀公，正欲以兴唐、虞之治于春秋，而子思以继大舜、文、武、周公之后者，亦以明其所传之一致耳。后世有能举而行之，则二帝、三王之治，岂外是哉！斯固子思之意也。", "bai": "", "page": 2672}, {"type": "meta", "wen": "禹思天下有溺者由己溺之也", "bai": "", "page": 2674}, {"type": "meta", "wen": "稷思天下有饥者由己饥之也", "bai": "", "page": 2674}, {"type": "para", "wen": "圣人各有忧民之念，而同其任责之心。夫圣人之忧民，其心一而已矣。所以忧之者，虽各以其职，而其任之于己也，曷尝有不同哉？昔孟子论禹、稷之急于救民而原其心，以为大禹之平水土也，虽其所施，无非决川距海之功，而民可免于昏垫矣；然其汲汲之心，以为天下若是其广也，吾之足迹既有所未到之地，则夫水之未治者，亦必有之矣；水之泛滥，既有所不免之地，则夫民之遭溺者，亦容有之矣；夫民之陷溺，由水之未治也，吾任治水之责，使水有不治，以溺吾民，是水之溺民，即吾之溺民也；民之溺于水，实吾之溺之也，吾其救之，可不急乎？后稷之教稼穑也，虽其所为无非播时百谷之事，而民可免于阻饥矣。然其遑遑之心，以为万民若是其众也，吾之稼穑，固未能人人而面诲矣，能保其无不知者乎？民之树艺，即未能人人而必知矣，能保其无不饥者乎？夫民之有饥，由谷之未播也，吾任播谷之责，使谷有未播以饥吾民，是饥之厄民，即吾之厄民也，民之饥于食，实吾之饥之也，吾其拯之，可以缓乎？夫禹、稷之心，其急于救民盖如此，此其所以虽当治平之世，三过其门而不入也欤！虽然，急于救民者，固圣贤忧世之本心，而安于自守者，又君子持己之常道。是以颜子之不改其乐，而孟子以为同道于禹、稷者，诚以禹、稷、颜子莫非素其位而行耳。后世各徇一偏之见，而仕者以趋时为通达，隐者以忘世为高尚，此其所以进不能忧禹、稷之忧，而退不能乐颜子之乐也欤！", "bai": "", "page": 2674}, {"type": "heading", "wen": "易", "bai": "", "page": 2676}, {"type": "heading", "wen": "先天而天弗违后天而奉天时", "bai": "", "page": 2677}, {"type": "para", "wen": "大人于天，默契其未然者，奉行其已然者。夫大人与天，一而已矣。然则默契而奉行之者，岂有先后之间哉？昔《文言》申《乾》九五爻义而及此意，谓大人之于天，形虽不同，道则无异。自其先于天者言之，时之未至，而道隐于无，天未有为也；大人则先天而为之，盖必经纶以造其端，而心之所欲，暗与道符，裁成以创其始，而意之所为，默与道契。如五典未有也，自我立之，而与天之所叙者，有吻合焉；五礼未制也，以义起之，而与天之所秩者，无差殊焉，天何尝与之违乎？以其后于天者言之，时之既至，而理显于有，天已有为也，大人则后天而奉之，盖必穷神以继其志，而理之固有者，只承之而不悖，知化以述其事，而理之当行者，钦若之而不违。如天叙有典也，立为政教以道之，五典自我而敦矣；天秩有礼也，制为品节以齐之，五礼自我而庸矣。我何尝违于天乎？是则先天不违，大人即天也；后天奉天，天即大人也；大人与天，其可以二视之哉？此九五所以为天下之利见也欤？大抵道无天人之别，在天则为天道，在人则为人道，其分虽殊，其理则一也。众人牿于形体，知有其分而不知有其理，始与天地不相似耳。惟圣人纯于义理，而无人欲之私，其礼即天地之体，其心即天地之心，而其所以为之者，莫非天地之所为也。故曰：“循理则与天为一。”", "bai": "", "page": 2677}, {"type": "heading", "wen": "河出图洛出书圣人则之", "bai": "", "page": 2678}, {"type": "para", "wen": "天地显自然之数，圣人法之以作经焉。甚矣！经不徒作也。天地不显自然之数，则圣人何由而法之以作经哉？《大传》言卜筮而推原圣人作《易》之由，其意盖谓《易》之用也不外乎卜筮，而《易》之作也则法乎《图》、《书》。是故通于天者河也，伏羲之时，天降其祥，龙马负《图》而出，其数则以五生数统五成数而同居其方，是为数之体焉。中于地者洛也，大禹之时，地呈其瑞，神龟载《书》而出，其数则以五奇数统四偶数而各居其所，是为数之用焉。《图》、《书》出矣，圣人若何而则之？彼伏羲则图以画卦，虚五与十者，太极也；积二十之奇，而合二十之偶，以一二三四而为六七八九，则仪象之体立矣；析四方之合以为乾、坤、坎、离，补四隅之空以为兑、震、巽、艮，则八卦之位定矣。是其变化无穷之妙，何莫而不本于图乎？大禹则《书》以叙畴，实其中五者，皇极也；一五行而二五事，三八政而四五纪，第于前者，有序而不乱也；六三德而七稽疑，八庶征而九福极，列于后者，有条而不紊也。是其先后不易之序，何莫而不本于《书》乎？吁！圣人之作《易》，其原出于天者如此，而卜筮之用所以行也欤！大抵《河图》、《洛书》相为经纬，八卦九章相为表里，但伏羲先得乎《图》以画卦。无所待于《书》；大禹独得乎《书》以叙畴，不必考于《图》耳。若究而言之，则《书》固可以为《易》，而《图》亦可以作《范》，又安知《图》之不为《书》，《书》之不为《图》哉？噫！理之分殊，非深于造化者，其孰能知之。", "bai": "", "page": 2678}, {"type": "heading", "wen": "书", "bai": "", "page": 2680}, {"type": "heading", "wen": "王懋昭大德建中于民以义制事以礼制心垂裕后昆予闻曰能自得师者王", "bai": "", "page": 2681}, {"type": "para", "wen": "大臣告君，即勉其修君道以贻诸后，必证以隆师道而成其功。夫君道之修，未有不隆师道而能致者也。大臣之论如此，其亦善于告君者哉！吾想其意，若谓新德固所以属人心，而建中斯可以尽君道，吾王其必勤顾之功，以明其德，求此中之全体，而自我建之，以为斯民之极也；操日跻之敬，以明夫善，尽此中之妙用，而自我立之，以为天下之准也。然中果何自而建邪？彼中见于事，必制以吾心之裁制，使动无不宜，而后其用行矣；中存于心，必制以此理之节文，使静无不正，而后其体立矣。若是，则岂特可以建中于民而已邪？本支百世，皆得以承懿范于无穷，而建中之用，绰乎其有余裕矣。子孙千亿，咸得以仰遗矩于不坠，而建中之推，恢乎其有余地焉。然是道也，非学无以致之。盖古人之言，以为传道者师之责，人君苟能以虚受人，无所拂逆，则道得于己，可以为建极之本，而王者之业，益以昌大矣。考德者师之任，人君果能愿安承教，无所建拒，则德成于身，足以为立准之地，而王者之基，日以开拓矣。是则君道修，而后其及远。师道立，而后其功成。吾王其可以不勉于是哉！抑尝反覆仲虺此章之旨，懋德建中，允执厥中之余绪也；制心制事，制外养中之遗法也。至于“能自得师”之一语，是又心学之格言、帝王之大法。则仲虺之学，其得于尧、舜之所授受者深矣！孟子叙道统之传，而谓伊尹、莱朱为见而知者，而说者以莱朱为仲虺，其信然哉！", "bai": "", "page": 2681}, {"type": "heading", "wen": "继自今立政其勿以人其惟吉士", "bai": "", "page": 2683}, {"type": "para", "wen": "大臣勉贤王之为治，惟在严以远小人，而专于任君子也。盖君子小人之用舍，天下之治忽系焉，人君立政，可不严于彼专于此哉？周公以是而告成王，意岂不曰，立政固在于用人，而非人适所以乱政？彼吉士之不可舍，而人之不可用，盖自昔而然矣。继今以立政，而使凡所以治其民者不致苟且而因循，则其施为之详，固非一人所能任也，而将何所取乎？继此以立政，而使凡所谓事与法者，不致懈怠而废弛，则其料理之烦，亦非独力所能举也，而将何所用乎？必其于人也，去之而勿任；于吉士也，任之而勿疑，然后政无不立矣。盖所谓人者，行伪而坚，而有以饰其诈，言非而辩，而有以乱其真者也，不有以远之，将以妨吾之政矣；必也严防以塞其幸入之路，慎选以杜其躁进之门，勿使得以戕吾民，坏吾事，而挠吾法焉。所谓吉士者，守恒常之德，而利害不能怵，抱贞吉之操，而事变不能摇者也，不有以任之，无以成吾之治矣；必也推诚信而彼此之不疑，隆委托而始终之无间，务使得以安吾民，济吾事，而平吾法焉。吁！严以去之，则小人无以投其衅；专以任之，则君子有以成其功；国家之治也，其以是欤！抑考之于《书》，禹、益、伊、傅、周、召之告君，至君子小人之际，每致意焉。盖君德之隆替，世道之升降，其原皆出于此，非细故也。秦、汉以下，论列之臣，鲜知此义，惟诸葛孔明之言曰：“亲君子远小人，先汉所以兴隆也。”其意独与此合，故论者以为三代之遗才云。", "bai": "", "page": 2683}, {"type": "heading", "wen": "诗", "bai": "", "page": 2685}, {"type": "heading", "wen": "不遑启居狁之故", "bai": "", "page": 2685}, {"type": "para", "wen": "戍者自言劳之未息，由患之未息也。夫狁之患，不可以不备，则戍役之劳，自有所不免矣。王者于遣戍之时，而代为之言若此，所谓“叙其情而风之以义”者欤！此诗之意，盖谓人固有不能忘之情，然亦有不容已之义；彼休息之乐，吾岂独无其情乎？启居之安，吾宁独无其念乎？诚以王命出戍，则此身既已属之军旅，而势不容于自便耳，是以局促行伍之间，奔走风尘之下。师出以律，而号令之严其敢违？军法有常，而更代之期何敢后？则吾虽有休息之情，而固所不暇矣；虽怀启居之念，而亦所不遑矣。然此岂上人之故欲困我乎？岂吾君之必欲劳我乎？诚以狁猾夏，则是举本以卫夫生灵，而义不容于自已耳。彼其侵扰疆场之患虽亦靡常，而凭陵中国之心实不可长，使或得肆猖獗，则腥膻之忧，岂独在于廊庙？如其乘间窃发，则涂炭之苦，遂将及于吾民。是我之不遑休息者，无非保乂室家，而狁之是备也；我之不暇启居者，无非靖安中国，而外寇之是防也。吁！叙其勤苦悲伤之情，而风以敌忾勤王之义，周王以是而遣戍役，此其所以劳而不怨也欤！大抵人君之为国，好战则亡，忘战则危，故用兵虽非先王之得已，而即戎之训亦有所不敢后也。观此诗之遣戍，不独以见周王重于役民，悯恻哀怜不容已之至情，而亦可以见周之防御狁于平日者，盖亦无所不至。故狁之在三代，终不得以大肆其荼毒。后世无事懈弛，有事则张皇，戎之不靖也，有由然哉！", "bai": "", "page": 2685}, {"type": "heading", "wen": "孔曼且硕万民是若", "bai": "", "page": 2687}, {"type": "para", "wen": "新庙制以顺人心，诗人之颂鲁侯也。夫人君之举动，当以民心为心也，鲁侯修庙而有以顺乎民焉，诗人得不颂而美之乎？鲁人美僖公之修庙而作是诗及此，谓夫我公之修庙也，材木尽来、甫之良，经画殚奚斯之虑。意以卑宫之俭，可以自奉，而非致孝乎鬼神，则新庙之作，虽甚曼焉，亦所宜矣。茅茨之陋，可以自处，而非敬事其先祖，则新庙之修，虽甚硕焉，亦非过矣。是以向之卑者，今焉增之使高，而体制极其巍峨，盖斯革斯飞，孔曼而长也；向之隘者，今焉拓之使广，而规模极其弘远，盖闲如奕如，且硕而大也。然庙制之极美者，岂独以竭我公之孝思？实所以从万民之仰望。盖以周公皇祖，德洽下民，而庙之弗称，固其所愿改作也，今之孔曼，亦惟民之所欲是从耳。泽流后世，而庙之弗缉，固其所愿修治也。今之孔硕，亦惟吾民之所愿是顺耳。是以向之有憾于弗称者，今皆翕然而快睹，莫不以为庙之曼者宜也，非过也；向之致怨于弗缉者，今皆欣然而满望，莫不以为庙之硕者，非过也，宜也。吁！庙制修于上，而民心顺于下，则其举事之善，于此可见，而鲁公之贤，亦可想矣。抑考鲁之先君，自伯禽以下，所以怀养其民人者，无非仁爱忠厚之道，而周公之功德，尤有以衣被而渐渍之，是以其民久而不忘，虽一庙之修，亦必本其先世之泽而颂祷焉。降及秦、汉干戈之际，尚能不废弦诵，守礼义，为主死节，而汉高不敢加兵。圣人之泽，其远矣哉！", "bai": "", "page": 2687}, {"type": "heading", "wen": "春秋", "bai": "", "page": 2689}, {"type": "meta", "wen": "宣公十一年", "bai": "", "page": 2689}, {"type": "heading", "wen": "楚子入陈楚子围郑晋荀林父帅师及楚子战于邲晋师败绩楚子灭萧晋", "bai": "", "page": 2689}, {"type": "meta", "wen": "俱宣公十二年人宋人卫人曹人同盟于清丘", "bai": "", "page": 2689}, {"type": "para", "wen": "外兵顺，而伯国自亵其威，既可贬；外兵黩，而伯国徒御以信，尤可讥。此楚以争伯为心，而晋失待之之道，《春秋》所以两示其法也。自夫晋景无制中夏之略，而后楚庄有窥北方之图，始焉县陈，以讨罪也，而征舒就戮；继焉入郑，以贰己也，而潘尫遂盟。一则讨晋之所未讨，一则平郑之所欲平，是虽未免以力假仁，然其义则公，其辞则顺矣。晋欲强之，必修德以俟，观衅而动，斯可也，顾乃兴无名之师，而师之以林父，楚子退师矣，而犹欲与之战，先縠违命矣，而不能行其辟；遂致邲战既北，而晋遂不支。则是主晋之师者，林父也，弃晋之师者，林父也，责安所逃乎？《春秋》于陈书入，于郑书围者，所以减楚之罪，而于邲之战，则独书林父以主之，用以示失律丧师之戒也。自夫晋人之威既亵，而后楚人之势益张，伐萧不已，而围其城，围萧不已，而溃其众，以吞噬小国之威，为恐动中华之计，是其不能以礼制心，而其志已盈，其兵已黩矣。晋欲御之，必信任仁贤，修明政事，斯可也；顾乃为清丘之盟，而主之以先縠，不能强于为善，而徒刑牲歃血之是崇；不能屈于群策，而徒要质鬼神之是务；故其盟亦随败，而晋卒不竞，则是主斯盟者，丧师之縠也，同斯盟者，列国之卿也，责安所归乎？《春秋》不称萧溃，特以灭书者，所以断楚之罪；而清丘之盟，则类贬列卿，而人之用，以示谋国失职之戒也。吁！楚庄之假仁，晋景之失策，不待言说，而居然于书法见之，此《春秋》之所以为化工欤！抑又论之：仗义执言，桓、文之所以制中夏者也。晋主夏盟，虽世守是道，犹不免为三王之罪人，而又并其先人之家法而弃之，顾汲汲于会狄伐郑，而以讨陈遗楚，使楚得风示诸侯于辰陵，则是时也，虽邲之战不败，清丘之盟不渝，而大势固已属之楚矣。呜呼！孔子沐浴之请，不用于哀公而鲁替；董公缟素之说，见用于高帝而汉兴，愚于是而重有感也。", "bai": "", "page": 2689}, {"type": "heading", "wen": "楚子蔡侯陈侯许男顿子沈子徐人越人伐", "bai": "", "page": 2692}, {"type": "meta", "wen": "昭公五年吴", "bai": "", "page": 2692}, {"type": "para", "wen": "《春秋》纪外兵而特进夫远人，以事有可善，而类无可绝也。盖君子与人为善，而世类之论，亦所不废也。然则徐、越从楚伐吴，而《春秋》进之者，非以此哉！慨夫庆封就戮，楚已见衔于吴东，鄙告入，吴复致怨于楚，至是楚子内搂诸侯，外连徐、越，而有伐吴之役。然何以见其事有可善邪？盖庆封之恶，齐之罪人也，吴子纳而处之，是为崇恶，楚子执而戮之，是为讨罪，彼曲此直，公论已昭于当时矣。夫何吴子违义举兵，困三邑之民，报朱方之憾，岂非狄道哉？楚子率诸侯以伐之，声崇恶之过，问违义之由，是乃以有名而讨无名，以无罪而讨有罪也，揆之彼善于此之义，固有可善者矣。又何以见其类无可绝邪？盖徐、越之夷，夏之变于夷者也，徐本伯益之后，越本大禹之后，元德显功，先世尝通于周室矣，惟其后人渎礼称王，甘心于僭伪，得罪于典常，故为狄道耳。君子正王法以黜之，上虽不使与中国等，下亦不使与夷狄均，盖以后人之僭伪，固法所不贷，而先世之功德，亦义所不泯也；揆之赏延于世之典，殆非可绝者欤！夫事既有可善，类又无可绝，故越始见经，而与徐皆得称人，圣人以为楚之是伐，比吴为善，其从之者，又皆圣贤之后，则进而称人可也。", "bai": "", "page": 2692}, {"type": "para", "wen": "《春秋》之慎于绝人也如是。夫抑论吴、楚，在《春秋》亦徐、越而已矣。吴以泰伯之后而称王，楚以祝融之后而称王，故《春秋》亦以待徐、越者待之，猾夏则举号，慕义则称人，及其浸与盟会，亦止于称子，曾不得以本爵通焉。盖待之虽恕，而其法固未始不严也。然则僭伪者，其能逃于《春秋》之斧钺邪！", "bai": "", "page": 2693}, {"type": "heading", "wen": "礼记", "bai": "", "page": 2694}, {"type": "heading", "wen": "君子慎其所以与人者", "bai": "", "page": 2694}, {"type": "para", "wen": "君子之所谨者，交接之道也。夫君子之与人交接，必有其道矣，于此而不谨，乌能以无失哉！记礼器者，其旨若曰：“观礼乐而知夫治乱之由。”故君子必慎夫交接之具。君子之与人交接也，不有礼乎？而礼岂必玉帛之交错？凡事得其序者皆是也。礼之得失，人之得失所由见，是礼在所当慎矣。不有乐乎？而乐岂必钟鼓之铿锵？凡物得其和者皆是也。乐之邪正，人之邪正所从著，是乐在所当慎矣。君子于和序之德，固尝慎之于幽独之地，而于接人之际，又和序之德所从见也，其能以无慎乎？君子于礼乐之道，固尝谨之于制作之大，而于与人之时，亦礼乐之道所由寓也，其可以不谨乎？故其与人交接也，一举动之微，若可忽矣，而必竞竞焉常致其检束，务有以比于礼而比于乐。其与人酬酢也，一语默之细，若可易矣，而必业业焉恒存夫戒谨，务有以得其序而得其和，所与者乡邦之贱士，而其笑语卒获，肃然大宾，是接也，况其所与之尊贵乎？所对者，闾阎之匹夫，而其威仪卒度，严乎大祭，是承也，况其所对之严惮乎？君子之慎其所以与人者如此，此其所以动容周旋，必中夫礼乐，而无失色于人也欤！抑论礼乐者，与人交接之具；慎独者，与人交接之本也。君子戒慎于不睹不闻，省察于莫见莫显，使其存于中者，无非中正和乐之道，故其接于物者，自无过与不及之差。昔之君子，乃有朝会聘享之时，至于失礼而不自觉者，由其无慎独之功，是以阳欲掩之，而卒不可掩焉耳。故君子而欲慎其所以与人，必先慎独而后可。", "bai": "", "page": 2694}, {"type": "heading", "wen": "心好之身必安之君好之民必欲之", "bai": "", "page": 2696}, {"type": "para", "wen": "内感而外必应，上感而下必应。夫君之于民，犹心之于身也；虽其内外上下之不同，而感应之理何尝有异乎？昔圣人之意，谓夫民以君为心也，君以民为体也，体而必从夫心，则民亦必从夫君矣。彼其心具于内，而体具于外，内外之异势，若不相蒙矣；然心惟无好则已，一有所好，而身之从之也，自有不期然而然。如心好夫采色，则目必安夫采色；心好夫声音，则耳必安夫声音；心而好夫逸乐，则四肢亦惟逸乐之是安矣。发于心而慊于己，有不勉而能之道也；动于中而应于外，有不言而喻之妙也。是何也？心者身之主，心好于内，而体从于外，斯亦理之必然欤！若夫君之于民，亦何以异于是？彼其君居于上，而民居于下，上下之异分，若不相关矣；然君惟无好则已，一有所好，而民之欲之也，亦有不期然而然。如君好夫仁，则民莫不欲夫仁；君好夫义，则民莫不欲夫义；君而好夫暴乱，则民亦惟暴乱之是欲矣。倡于此而和于彼，有不令而行之机也；出乎身而加乎民，有不疾而速之化也。是何也？君者民之主，君好于上，而民从于下，固亦理之必然欤！是则内外上下本同一体，而此感彼应，自同一机，人君之于民也，而可不慎其所以感之邪？抑论之，身固必从乎心矣；民固必从乎君矣；抑孰知心之存亡，有系于身，而君之存亡，有系于民乎？为人君者，但知下之必从夫上，而不知上之存亡有系于下，则将恣己徇欲，惟意所为，而亦何所忌惮乎？故夫子于下文必继之曰：“君以民存，亦以民亡。”噫，可惧乎！", "bai": "", "page": 2696}, {"type": "heading", "wen": "论", "bai": "", "page": 2698}, {"type": "heading", "wen": "人君之心惟在所养", "bai": "", "page": 2699}, {"type": "para", "wen": "人君之心，顾其所以养之者何如耳？养之以善，则进于高明，而心日以智；养之以恶，则流于污下，而心日以愚。故夫人君之所以养其心者，不可以不慎也。天下之物，未有不得其养而能生者，虽草木之微，亦必有雨露之滋，寒暖之剂，而后得以遂其畅茂条达。而况于人君之心，天地民物之主也，礼乐刑政教化之所自出也，非至公无以绝天下之私，非至正无以息天下之邪，非至善无以化天下之恶，而非其心之智焉，则又无以察其公私之异，识其邪正之归，辩其善恶之分；而君心之智否，则固系于其所以养之者也，而可以不慎乎哉？君心之智，在于君子之养之以善也；君心之愚，在于小人之养之以恶也。然而君子小人之分，亦难乎其为辩矣。人心惟危，道心惟微，尧、舜之相授受而所以叮咛反覆者，亦维以是；则夫人君之心，亦难乎其为养矣。而人君一身，所以投间抵隙而攻之者，环于四面，则夫君心之养，固又难乎其无间矣。是故必有匡直辅翼之道，而后能以养其心；必有洞察机微之明，而后能以养其心；必有笃确精专之诚，而后能以养其心；斯固公私之所由异，邪正之所从分，善恶之所自判，而君心智愚之关也。世之人君，孰不欲其心之公乎？然而每失之于邪也；孰不欲其心之善乎？然而每失之于恶也。是何也？无君子之养也。养之以君子，而不能不间之以小人也，则亦无惑乎其心之不智矣。昔者太甲颠覆典刑，而卒能处仁迁义，为有商之令主，则以有伊尹之圣以养之；成王孺子襁褓，而卒能祗勤于德，为成周之盛王，则以有周公之圣以养之；桀、纣之心，夫岂不知仁义之为美，而卒不免于荒淫败度，则其所以养之者，恶来、飞廉之徒也。呜呼！是亦可以知所养矣。人虽至愚也，亦宁无善心之萌？虽其贤智也，亦宁无恶心之萌？于其善心之萌也，而有贤人君子扩充培植于其间，则善将无所不至，而心日以智矣；于其恶心之萌也，而有小夫人引诱逢迎于其侧，则恶亦无所不至，而心日以愚矣。故夫人君而不欲其心之智焉，斯已矣；苟欲其心之智，则贤人君子之养，固不可一日而缺也。何则？人君之心，不公则私，不正则邪，不善则恶，不贤人君子之是与，则小夫人之是狎，固未有漠然中立而两无所在者。一失其所养，则流于私，而心之智荡矣。入于邪，而心之智惑矣；溺于恶，而心之智亡矣；而何能免于庸患之归乎？夫惟有贤人君子以为之养，则义理之学，足以克其私心也；刚大之气，足以消其邪心也；正直之论，足以去其恶心也。扩其公而使之日益大，扶其正而使之日益强，作其善而使之日益新，夫是之谓匡直辅翼之道，而所以养其心者有所赖。然而柔媚者近于纯良，而凶者类于刚直，故士有正而见斥，人有而获进，而卒无以得其匡直辅翼之资，于是乎慎择而明辨，必使居于前后左右者无非贤人君子，而不得有所混淆于其间，夫是之谓洞察几微之明，而所以养其心者无所惑。然而耿直者难从，而谄谀者易入也；拂忤者难合，而阿顺者易亲也；则是君子之养未几，而小人之养已随；养之以善者方退，而养之以恶者已入。故夫人君之于贤士君子，必信之笃，而小人不得以间；任之专，而邪佞不得以阻；并心悉虑，惟匡直辅翼之是资焉，夫是之谓笃确专一之诚。而所以养其心者，不至于有鸿鹄之分，不至于有一暴十寒之间，夫然后起居动息，无非贤士君子之与处，而所谓养之以善矣。夫然后私者克而心无不公矣，邪者消而心无不正矣，恶者去而心无不善矣。公则无不明，正则无不达，善则无不通，而心无不智矣。夫然后可以绝天下之私，可以息天下之邪，可以化天下之恶，可以兴礼乐，修教化，而为天地民物之主矣。而此何莫而不在于其所养邪！何莫而不在于养之以善邪！人君之心，惟在所养，范氏之说，盖谓养君心者言也，而愚之论，则以为非人君有洞察之明、专一之诚，则虽有贤士君子之善养，亦无从而效之，而犹未及于人君之所以自养也。然必人君自养其心，而后能有洞察之明，专一之诚以资夫人，而其所以自养者，固非他人之所能与矣，使其勉强于大庭昭晰之时，有放纵于幽独得肆之地，则虽有贤人君子，终亦无如之何者，是以人君尤贵于自养也。若夫自养之功，则惟在于存养省察，而其要又不外乎持敬而已。愚也请以是为今日献。", "bai": "", "page": 2699}, {"type": "heading", "wen": "表", "bai": "", "page": 2704}, {"type": "meta", "wen": "开元二十四年", "bai": "", "page": 2704}, {"type": "heading", "wen": "拟唐张九龄上千秋金鉴录表", "bai": "", "page": 2704}, {"type": "para", "wen": "开元二十四年八月五日，具官臣张九龄上言：恭遇千秋圣节，谨以所撰《千秋金鉴录》进呈者。臣九龄诚惶诚恐，顿首顿首：", "bai": "", "page": 2704}, {"type": "para", "wen": "伏以古训有获，成宪无愆，自昔致治之明君，莫不师资于往典，故武王有《洪范》之访，而高宗起旧学之思。兹盖伏遇皇帝陛下，乃武乃文，好问好察，赤龙感唐尧之端，白鱼兆周武之兴，是以诞应五百载之昌期，而能起绍亿万年之大统。时维八月，节届千秋，凡兹鼎轴之臣，皆有宝镜之献，祝颂所寓，恭敬是将。臣九龄学本面墙，忠存自牖，窃谓群臣所献，虽近正冠之喻，揆诸事君以礼，尚亏懋德之规。顾瓌奇之珍，则尚方所自有，而珠玉是宝，虽诸侯以为殃。仰窥文皇“以人为鉴”之谟，窃取伏羲制器尚象之义，覃思古昔，效法丹书，粗述废兴，谬名《金鉴》。盖搜寻旧史，无非金石之言；而采掇前闻，颇费陶镕之力；躬铅椠以实录，敢粉饰乎虚文？鼓铸尧舜之模，炉冶商周之范；考是非之迹，莫遁妍媸；观兴替所由，真如形影。彼《六经》之道，夫岂不明？而诸子之谈，亦宁无见？顾恐万机之弗暇，愿摅一得而少裨，虽未能如贾山之《至言》，或亦可方陆生之《新语》。善可循而恶可戒，情状具在目前；乱有始而治有源，仪刑视诸掌上。公私具烛，光涵阳德之精；幽隐毕陈，寒照阴邪之胆。盖华封之祝，未罄于三，而魏征所亡，聊献其一。若陛下能自得师，或亦可近取诸此，视远亦维明矣，反观无不了然。诚使不蔽于私，自当明见万里；终能益磨以义，固将洞察纤毫。维兹昧爽所需，用为缉熙之助。伏愿时赐披阅，无使遂掩尘埃。宜监于殷，励周宣之明发；顾天命，效成汤之日新；永惟丕显之昭昭，庶识微衷之耿耿。月临日照，帝德运于光天；岳峙川流，圣寿同于厚地！臣无任瞻天仰圣激切屏营之至！谨以所述《千秋金鉴录》随表上进以闻。", "bai": "", "page": 2705}, {"type": "heading", "wen": "策五道", "bai": "", "page": 2707}, {"type": "para", "wen": "问：王者功成作乐，治定制礼，故功大者乐备，治遍者礼具，而五帝不沿乐，三王不袭礼也。自汉而下，礼乐日衰，既不能祖述宪章，以复三代之旧制，则亦不过苟且因循，以承近世之陋习而已。盖有位无德，固宜其然也。惟我太祖、太宗，以圣人在天子之位，故其制作之隆，卓然千古，诚有不相沿袭者，独其广大渊微，有非世儒所能测识耳。夫合九庙而同堂，其有仿于古乎？一郊社而并祭，其有见于经乎？声容之为备，而郊祭之舞，去干戚以为容，雅颂之为美，而燕享之乐属教坊以司颂，是皆三代所未闻而创为之者。然而治化之隆，超然于三代之上，则其间固宜自有考诸三王而不谬者，而非圣人其孰能知之？夫鲁，吾夫子之乡，而先王之礼乐在焉。夫子之言曰：“吾学周礼，今用之，吾从周。”斯固鲁人之所世守也。诸士子必能明言之。", "bai": "", "page": 2707}, {"type": "para", "wen": "圣人之制礼乐，非直为观美而已也；固将因人情以为之节文，而因以移风易俗也。夫礼乐之说，亦多端矣，而其大意，不过因人情以为之节文。是以礼乐之制，虽有古今之异，而礼乐之情，则无古今之殊。《传》曰：“知礼乐之情者能作，识礼乐之文者能述。作者之谓圣，述者之谓明，故夫钟鼓管磬、羽籥干戚者，乐之器也；屈伸俯仰、缀兆舒疾者，乐之文也；簠簋俎豆、制度文章者，礼之器也；升降上下、周旋裼袭者，礼之文也。”夫所谓礼乐之情者，岂徒在于钟鼓、干戚、簠簋、制度之间而已邪？岂徒在于屈伸、缀兆、升降、周旋之间而已邪？后世之言礼乐者，不本其情，而致详于形器之末，是以论明堂，则惑于吕氏《考工》之说；议郊庙，而局于郑氏、王肃之学。钟吕纷争于秬黍，而尺度牵泥于周天，纷纷籍籍，卒无一定之见，而礼乐亦因愈以废坠，是岂知礼乐之大端，不过因人情而为之节文者乎？《传》曰：“礼也者，义之实也，协诸义而协则礼，虽先王未之有，可以义起也。”孟子曰：“今之乐，犹古之乐也。”今夫行礼于此，而有以即夫人心之安焉，作乐于此，而使闻之者欣欣然有喜色焉，则虽义起之礼，世俗之乐，其亦何异于古乎？使夫行礼于此，而有以大拂乎人之情，作乐于此，而闻之者疾首蹙额而相告也，则虽折旋周礼，而戛击《咸》、《韶》，其亦何补于治乎？即是说而充之，则执事之所以下询者，虽九庙异制可也，合而同堂亦可也，郊社异地可也，一而并祭亦可也。声容之备固善矣，而苟有未备焉，似亦无伤也；雅颂之纯固美矣，而苟有未纯焉，或亦无患也。呜呼！此我太祖、太宗之所以为作者之圣，而有以深识夫礼乐之情者欤！窃尝伏观祖宗之治化功德，荡荡巍巍，蟠极天地之外，真有以超越三代而媲美于唐虞者。使非礼乐之尽善尽美，其亦何以能致若是乎？草莽之臣，心亦能知其大，而口莫能言之，故尝以为天下之人，苟未能知我祖宗治化功德之隆，则于礼乐之盛，固宜其有所未识矣。虽然，先王之制，则亦不可以不讲也。《祭法》“天子七庙，三昭三穆，与太祖之庙而七，益以文武世室而为九，庙门皆南向，主皆东向，各擅一庙之尊，而昭穆不紊焉”，则周制也。郊社之礼，天尊而地卑，郊以大报天，而社以神地道，故燔柴于泰坛，祭天也；瘗埋于泰折，祭地也；其不并祭久矣。祭天之用乐，则吕氏《月令》以仲夏“命乐师修鞀鞞鼓，均琴瑟管箫，执干戚戈羽，调竽笙篪簧，饬钟磬柷敔，而用盛乐以大雩帝”。则祭天之乐，有干戚戈羽矣。子夏告魏文侯以古乐，以为进旅退旅，和正以广，弦匏笙簧，会守拊鼓，始奏以文，复乱以武，治乱以相，讯疾以雅，而所谓及优侏儒者，谓之新乐。夫国家郊庙之礼，虽以义起，固亦不害其为协诸义而协矣。虽然，岂若协于义而合于古之为尤善乎？国家祀享之乐，虽不效古，固亦不害其为因人情而为之饰矣。虽然，岂若因人情而又合于古之尤善乎？昔者成周之礼乐，至周公而始备，其于文武之制，过者损之，不及者益焉，而后合于大中至正。此周公所以为善继善述，而以达孝称也。儒生稽古之谈，固未免于拘滞，所敢肆其狂言，则恃有善继善述之圣天子在上也。", "bai": "", "page": 2708}, {"type": "para", "wen": "问：佛、老为天下害，已非一日，天下之讼言攻之者，亦非一人矣，而卒不能去，岂其道之不可去邪？抑去之而不得其道邪？将遂不去，其亦不足以为天下之患邪？夫今之所谓佛、老者，鄙秽浅劣，其妄初非难见，而程子乃以为比之杨、墨，尤为近理；岂其始固自有说，而今之所习者，又其糟粕之余欤？佛氏之传，经传无所考，至于老子，则孔子之所从问礼者也，孔子与之同时，未尝一言攻其非，而后世乃排之不置，此又何欤？夫杨氏之为我，墨氏之兼爱，则诚非道矣，比之后世贪冒无耻，放于利而行者，不有间乎？而孟子以为无父无君，至比于禽兽，然则韩愈以为佛、老之害甚于杨、墨者，其将何所比乎？抑不知今之时而有兼爱、为我者焉，其亦在所辟乎？其将在所取乎？今之时不见有所谓杨、墨者，则其患止于佛、老矣；不知佛、老之外尚有可患者乎？其无可患者乎？夫言其是，而不知其所以是，议其非，而不识其所以非，同然一辞而以和于人者，吾甚耻之。故愿诸君之深辨之也。", "bai": "", "page": 2712}, {"type": "para", "wen": "天下之道，一而已矣，而以为有二焉者，道之不明也。孔子曰：“道之不明也，我知之矣，知者过之，愚者不及也；道之不行也，我知之矣，贤者过之，不肖者不及也。”呜呼！道一也，而人有知愚贤不肖之异焉，此所以有过与不及之弊，而异端之所从起欤？然则天下之攻异端者，亦先明夫子之道而已耳。夫子之道明，彼将不攻而自破，不然，我以彼为异端，而彼亦将以我为异端，譬之穴中之斗鼠，是非孰从而辨之？今夫吾夫子之道，始之于存养慎独之微，而终之以化育参赞之大；行之于日用常行之间，而达之于国家天下之远。人不得焉，不可以为人，而物不得焉，不可以为物，犹之水火菽帛而不可一日缺焉者也。然而异端者，乃至与之抗立而为三，则亦道之不明者之罪矣。道苟不明，苟不过焉，即不及焉。过与不及，皆不得夫中道者也，则亦异端而已矣。而何以攻彼为哉？今夫二氏之说，其始亦非欲以乱天下也，而卒以乱天下，则是为之徒者之罪也。夫子之道，其始固欲以治天下也，而未免于二氏之惑，则亦为之徒者之罪也。何以言之？佛氏吾不得而知矣；至于老子，则以知礼闻，而吾夫子所尝问礼，则其为人要亦非庸下者，其修身养性，以求合于道，初亦岂甚乖于夫子乎？独其专于为己而无意于天下国家，然后与吾夫子之格致诚正而达之于修齐治平者之不同耳。是其为心也，以为吾仁矣，则天下之不仁，吾不知可也；吾义矣，则天下之不义，吾不知可也。居其实而去其名，敛其器而不示之用，置其心于都无较计之地，而亦不以天下之较计动于其心。此其为念，固亦非有害于天下者，而亦岂知其弊之一至于此乎？今夫夫子之道，过者可以俯而就，不肖者可以企而及，是诚行之万世而无弊矣。然而子夏之后有田子方，子方之后为庄周，子弓之后有荀况，荀况之后为李斯，盖亦不能以无弊，则亦岂吾夫子之道使然哉？故夫善学之，则虽老氏之说无益于天下，而亦可以无害于天下；不善学之，则虽吾夫子之道，而亦不能以无弊也。今天下之患，则莫大于贪鄙以为同，冒进而无耻。贪鄙为同者曰：“吾夫子固无可无不可也。”冒进无耻者曰：“吾夫子固汲汲于行道也。”嗟乎！吾以吾夫子之道以为奸，则彼亦以其师之说而为奸，顾亦奚为其不可哉！今之二氏之徒，苦空其行，而虚幻其说者，既已不得其原矣；然彼以其苦空，而吾以其贪鄙；彼以其虚幻，而吾以其冒进；如是而攻焉，彼既有辞矣，而何以服其心乎？孟子曰：“经正则庶民兴，庶民兴，斯无邪慝矣。”今不皇皇焉自攻其弊，以求明吾夫子之道，而徒以攻二氏为心，亦见其不知本也夫！生复言之，执事以攻二氏为问，而生切切于自攻者，夫岂不喻执事之旨哉？《春秋》之道，责己严而待人恕；吾夫子之训，先自治而后治人也。若夫二氏与杨、墨之非，则孟子辟之于前，韩、欧诸子辟之于后，而岂复俟于言乎哉？执事以为夫子未尝攻老氏，则夫子盖尝攻之矣，曰：“乡愿，德之贼也。”盖乡愿之同乎流俗而合乎污世，即老氏之所谓“和其光而同其尘”者也；和光同尘之说，盖老氏之徒为之者，而老氏亦有以启之。故吾夫子之攻乡愿，非攻老氏也；攻乡愿之学老氏而又失之也。后世谈老氏者皆出于乡愿，故曰“夫子盖尝攻之也”。", "bai": "", "page": 2714}, {"type": "para", "wen": "问：古人之言曰：“志伊尹之所志，学颜子之所学。”诸君皆志伊学颜者，请遂以二君之事质之。夫伊尹之耕于有莘之野，而乐尧舜之道也，固将终身尔矣。汤之聘币三往，而始幡然以起，是岂苟焉者？而后世至以为割烹要汤，斯固孟子已有明辩；至于桀则固未尝以币聘尹也，而自往就之，至再至五，昔人谓其急于生人而往速其功也，果尔，其不类于以割烹要之欤！颜渊之学于孔子也，其详且要，无有过于四勿之训。兹四言者，今之初学之士皆自以为能知，而孔门之徒以千数，其最下者宜其犹愈于今之人也，何独唯颜子而后可以语此乎？至于箪瓢陋巷而不改其乐，此尤孔子之所深嘉屡叹而称以为贤者，而昔之人乃以为哲人之细事，将无类于今之初学自谓能知四勿之训者乎？夫尹也，以汤之圣，则三聘而始往，以桀之虐，则五就而不辞。颜之四勿，孔门之徒所未闻，而今之初学自以为能识箪瓢之乐。孔子以为难，而昔人以为易也，兹岂无其说乎？不然，则伊尹之志荒，而颜子之学浅矣。", "bai": "", "page": 2718}, {"type": "para", "wen": "求古人之志者，必将先自求其志，而后能辨其出处之是非；论古人之学者，必先自论其学，而后能识其造诣之深浅，此伊尹之志，颜子之学，所以未易于窥测也。尝观伊尹耕于有莘之野，而乐尧舜之道，固将终其身于畎亩，虽禄之以天下，有弗顾者。其后感成汤三聘之勤，而始幡然以起，是诚甚不易矣。而战国之士，犹以为割烹要汤，向非孟氏之辩，则千载之下，孰从而知其说之妄乎？至于五就桀之说，则尚有可疑者。孟子曰：“往役，义也；往见，不义也。”夫尹以庶人而往役于桀，可也；以行道而往就于桀，不可也。尹于成汤之圣，犹必待其三聘者，以为身不可辱，而道不可枉也。使尹不俟桀之聘而自往，则其辱身枉道也甚矣，而何以为伊尹乎？使尹之心以为汤虽圣臣也，桀虽虐君也，而就之，则既以为君矣，又可从而伐之乎？桀之暴虐，天下无不知者，彼置成汤之圣而弗用，尚何有于伊尹？使尹不知而就之，是不知也；知而就之，是不明也；就之而复伐之，是不忠也；三者无一可，而谓伊尹为之乎？柳宗元以为伊尹之五就桀，是大人之欲速其功。且曰：“吾观圣人之急生人，莫若伊尹，伊尹之大，莫大于五就桀。”苏子瞻讥之，以为宗元欲以此自解其从叔文之非，可谓得其心矣。然五就之说，孟子亦尝言之，而说者以为尹之就桀，汤进之也，则尹惟知以汤之心为心而已，是在圣人固必自有以处此；而愚以为虽诚有之，亦孟子所谓有伊尹之志则可耳。不然，吾未见其不为反覆悖乱之归也。至于颜子四勿之训，此盖圣贤心学之大，有未易以言者，彼其自谓能知，则譬之越南冀北，孰不知越之为南而冀之为北？至其道理之曲折险易，自非所尝经历莫从而识之也。今以四勿而询人，则诚未见其有不知者；及究其所谓非礼，则又莫不喑然而无以为答也。今夫天下之事，固有似礼而非礼者矣，亦有似非礼而实为礼者矣；其纤悉毫厘至于不可胜计，使非尽格天下之物而尽穷天下之理，则其疑似几微之间，孰能决然而无所惑哉？夫于所谓非礼者既有未辨，而断然欲以之勿视听言动，是亦告子之所谓不得于言而勿求于心耳，其何以能克己复礼而为仁哉？夫惟颜子博约之功已尽于平日，而其明睿所照，既已略无纤芥之疑，故于事至物来，天理人欲，不待议拟，而已判然，然后行之，勇决而无疑滞，此正所谓有至明以察其几，有至健以致其决者也。孔门之徒，自子贡之颖悟，不能无疑于一贯；则四勿之训，宜乎唯颜子之得闻也。若夫箪瓢之乐，则颜子之贤尽在于此，盖其所得之深者。周子尝令二程寻之，则既知其难矣。惟韩退之以为颜子得圣人为之依归，则其不忧而乐也岂不易？顾以为哲人之细事，初若无所难者，是盖言其外而未究其中也。盖箪瓢之乐，其要在于穷理，其功始于慎独。能穷理，故能择乎中庸，而复理以为仁；能慎独，故能克己不贰过，而至于三月不违。盖其人欲净尽，天理流行，是以内省不疚，仰不愧，俯不怍，而心广体胖，有不知其手舞足蹈者也。退之之学，言诚正而弗及格致，则穷理慎独之功，正其所大缺，则于颜子之乐，宜其得之浅矣。嗟乎！志伊尹之志也，然后能知伊尹之志；学颜子之学也，然后能知颜子之学。生亦何能与于此哉？顾其平日亦在所不敢自暴自弃，而心融神会之余，似亦微有所见，而执事今日之问，又适有相感发者，是以辄妄言之，幸执事不以为僭而教之也。", "bai": "", "page": 2719}, {"type": "para", "wen": "问：风俗之美恶，天下之治忽关焉。自汉以来，风俗之变而日下也，犹江河之日趋于海也，不知其犹可挽而复之古乎？将遂往而不返也，孔子谓齐一变至于鲁，鲁一变至于道，而说者以为二国之俗有美恶，故其变而之道也有难易。夫风俗之在三代也，不知其凡几变矣，而始为汉；其在汉也，又不知其凡几变矣，而始为唐为宋。就使屡变而上焉，不过为汉而上耳，为唐而止耳，而何以能遂复于三代乎？今之风俗，则贾谊之所太息者有之矣。皇上之德，过于汉文诸士，苟有贾生之谈焉，固所喜闻而乐道也。", "bai": "", "page": 2723}, {"type": "para", "wen": "天下之患，莫大于风俗之颓靡而不觉。夫风俗之颓靡而不觉也，譬之潦水之赴壑，浸淫泛滥，其始若无所患，而既其末也，奔驰溃决，忽焉不终朝而就竭。是以甲兵虽强，土地虽广，财赋虽盛，边境虽宁，而天下之治，终不可为，则风俗之颓靡，实有以致之。古之善治天下者，未尝不以风俗为首务，武王胜殷，未及下车，而封黄帝、尧、舜之后。下车而封王子比干之墓，释箕子之囚，式商容之闾。当是时也，拯溺救焚之政，未暇悉布，而先汲汲于为是者，诚以天下风俗之所关，而将以作兴其笃厚忠贞之气也。故周之富强不如秦，广大不如汉，而延世至于八百年者，岂非风俗之美致然欤！今天下之风俗，则诚有可虑者，而莫能明言之，何者？西汉之末，其风俗失之懦；东汉之末，其风俗失之激；晋失之虚；唐失之靡；是皆有可言者也。若夫今之风俗，谓之懦，则复类于悍也；谓之激，则复类于同也；谓之虚，则复类于琐也；谓之靡，则复类于鄙也。是皆有可虑之实，而无可状之名者也。生固亦有见焉，而又有所未敢言也。虽然，圣天子在上，贤公卿在位，于此而不直，是无所用其直矣。请遂言之：孔子曰：“乡愿，德之贼也。”孟子曰：“非之无举也，刺之无刺也，居之似忠信，行之似廉洁，同乎流俗，合乎污世，自以为是，而不可与入尧、舜之道，阉然媚于世者，是乡愿也。”盖今风俗之患，在于务流通而薄忠信，贵进取而贱廉洁，重儇狡而轻朴直，议文法而略道义，论形迹而遗心术，尚和同而鄙狷介；若是者，其浸淫习染既非一日，则天下之人固已相忘于其间而不觉，骤而语之，若不足以为患，而天下之患终必自此而起；泛而观之，若无与于乡愿，而徐而察之，则其不相类者几希矣。愚以为欲变是也，则莫若就其所藐者而振作之。何也？今之所薄者，忠信也，必从而重之；所贱者，廉洁也，必从而贵之；所轻者，朴直也，必从而重之；所遗者，心术也，必从而论之；所鄙者，狷介也，必从而尚之；然而今之议者，必以为是数者未尝不振作之也，则亦不思之过矣。大抵闻人之言，不能平心易气，而先横不然之念，未有能见其实然者也。夫谓是数者之未尝不振作之也，则夫今之所务者，果忠信欤？果流通欤？所贵者，果进取欤？果廉洁欤？其余者亦皆以是而思之，然后见其所谓振作之者，盖亦其名，而实有不然矣。今之议者，必且以为何以能得其忠信廉洁之实而振作之？则愚以为郭隗之事，断亦可见也。为人上者，独患无其诚耳。苟诚心于振作，吾见天下未有不翕然而向风者也。孟子曰：“伯夷，圣之清者也；柳下惠，圣之和者也；故闻伯夷之风者，顽夫廉，懦夫有立志；闻柳下惠之风者，鄙夫敦，薄夫宽。”夫夷、惠之风所以能使人闻于千载之下而兴起者，诚焉而已耳。今曰：“吾将以忠信廉洁振作天下，而中心有弗然焉。”则夫乡愿之所谓居之似忠信，而行之似廉洁者，固亦未尝无也。", "bai": "", "page": 2724}, {"type": "para", "wen": "问：明于当世之务者，惟豪杰为然，今取士于科举，虽未免于记诵文辞之间，然有司之意，固惟豪杰是求也。非不能钩深索隐以探诸士之博览，然所以待之浅矣，故愿相与备论当世之务。夫官冗矣而事益不治，其将何以厘之？赋繁矣而财愈不给，其将何以平之？建屏满于天下而赋禄日增，势将不掉，其将何以处之？清戎遍于海内而行伍日耗，其将何以筹之？蝗旱相仍，流离载道，其将何以拯之？狱讼烦滋，盗贼昌炽，其将何以息之？势家侵利，人情怨咨，何以裁之？戎、胡窥窃，边鄙未宁，何以攘之？凡此数者，皆当今之急务，而非迂儒曲士之所能及也，愿闻其说。", "bai": "", "page": 2728}, {"type": "para", "wen": "执事询当世之务，而以豪杰望于诸生，诚汗颜悚息，惧无以当执事之待。然执事之问，则不可虚也，生请无辞以对。", "bai": "", "page": 2729}, {"type": "para", "wen": "盖天下之患，莫大于纪纲之不振，而执事之所问者，未及也。夫自古纪纲之不振，由于为君者垂拱宴安于上，而为臣者玩习懈弛于下。今朝廷出片纸以号召天下，而百司庶府莫不震栗悚惧，不可谓纪纲之不振，然而下之所以应其上者，不过簿书文墨之间，而无有于贞固忠诚之实。譬之一人之身，言貌动止，皆如其常，而神气恍然，若有不相摄者，则于险阻烦难，必有不任其劳矣，而何以成天下之亹亹哉？故愚以为当今之务，莫大于振肃纪纲，而后天下之治可从而理也。是以先进纪纲之说，而后及执事之问。夫官冗而事不治者，其弊有三：朝廷之所以鼓舞天下而奔走豪杰者，名器而已。孔子曰：“惟名与器，不可以假人。”今者不能慎惜，而至或加之于异道邪之辈，又使列于贤士大夫之上，有志之士，吾知其不能与之齿矣。此豪杰之所以解体，而事之所以不治者，名器之太滥也。至于升授之际，不论其才之堪否，而概以年月名次之先后为序，使天下之人皆有必得之心，而无不可为之虑，又一事特设一官，或二人而共理一职，十羊九牧，徒益纷扰。至于边远疲弊之地，宜简贤能特加抚缉，功成绩著，则优其迁擢，以示崇奖，有志之士，亦亦无不乐为者，而乃反委之于庸劣，遂使日益凋瘵，则是选用太忽之过也。天下之治，莫急守令，而令之于民，尤为切近，昔汉文之时，为吏者长子孙居官，以职为氏，今者徒据纸上之功绩，亟于行取，而责效于二三年之间，彼为守令者，无是亦莫不汲汲于求去，而莫有诚确久远之图，此则求效太速之使然耳。赋繁而财不给者，此无益之费多，而冗食之徒众也；去是二者，而又均一天下之赋，使每郡各计其所入之数，而均之于田，不得有官民三则之异，则诡射之弊息，而赋亦稍平矣。至于建屏之议，尤为当今之切务，而天下之人莫敢言者，欲求善后之策，则在于朝廷之上，心于继志，而不以更改为罪；建议之臣，心于为国，而不以获罪自阻，然后可以议此。不然，虽论无益矣。盖昔者汉之诸侯，皆封以土地，故其患在强大而不分，分则易弱矣。今之藩国，皆给以食禄，故其患在众多而不合，合则易办矣。然晁错一言，而首领不保，天下虽悲错之以忠受戮，其谁复敢言乎？清戎之要，在于因地利而顺人情。盖南人之习于南，而北人之习于北，是谓地利。南之不安于北，而北之不安于南，是谓人情。今以其清而已得者就籍之于其本土，而以其清而不得者之粮，馈输之于边，募骁勇以实塞下，或亦两得之矣。蝗旱相仍而流离载道者，官冗而事益不治之所致也；狱讼繁滋而盗贼昌炽者，赋繁而财愈不给之所起也。势家侵利而人情怨咨，则在于制之以礼，而一转移于向背之间而已。昔田蚡请考工地以益宅，武帝怒曰：“何不遂取武库？”蚡惧而退。夫以田蚡之横，而武帝一言不敢复纵，况未及蚡者，诚有以禁戒惩饬之，其亦何敢肆无忌惮也哉？胡戎窥窃而边鄙未宁，则在于备之不预，而畏之太深之过也。夫戎虏之患，既深且久，足可为鉴矣；而当今之士，苟遇边报稍宁，则皆以为不复有事，解严弛备，恬然相安，以苟岁月，而所谓选将练兵，蓄财养士者，一旦置之度外，纵一行焉，亦不过取具簿书，而实无有于汲汲皇皇之意；及其一旦有事，则怆惶失措，若不能以终日。盖古之善御戎狄者，平居无怠忽苟且之心，故临事无纷张缪戾之患，兢惕以备之，谈笑以处之，此所以为得也。若夫制御之策，则古今之论详矣，在当事者择而处之，生不能别为之说也。夫执事之所以求士者，不专于记诵文辞之间，故诸生之文，亦往往出于科举之外，惟其说之或有足取，则执事幸采择之！", "bai": "", "page": 2729}, {"type": "heading", "wen": "山东乡试录后序", "bai": "", "page": 2733}, {"type": "para", "wen": "弘治甲子秋八月甲申，《山东乡试录》成，考试官刑部主事王守仁既序诸首简，所以纪试事者慎且详矣。鼎承乏执事后，有不容无一言以申告登名诸君子者。夫山东，天下之巨藩也。南峙泰岱，为五岳之宗，东汇沧海，会百川之流。吾夫子以道德之师，钟灵毓秀，挺生于数千载之上，是皆穷天地，亘古今，超然而独盛焉者也。然陟泰岱则知其高，观沧海则知其大，生长夫子之邦，宜于其道之高且大者有闻焉，斯不愧为邦之人矣！诸君子登名是录者，其亦有闻乎哉？夫自始学焉，读其书，聚而为论辩，发而为文词，至于今，资藉以阶尺寸之进而方来未已者，皆夫子之绪余也。独于道未之闻，是固学者之通患，不特是邦为然也。然海与岱，天下知其高且大也，见之真而闻之熟，必自东人始，其于道，则亦宜若是焉可也。且道岂越乎所读之书与所论辩而文词之者哉？理气有精粗，言行有难易，穷达有从违，此道之所以鲜闻也。夫海岱云者，形胜也；夫子之道德也者，根本也；虽若相参并立于天地间，其所以为盛，则又有在此而不在彼者矣。鼎实陋于闻道，幸以文墨从事此邦，冀所录之士，有是人也，故列东藩之盛，乐为天下道之。", "bai": "", "page": 2734}, {"type": "heading", "wen": "目录", "bai": "", "page": 2736}, {"type": "meta", "wen": "卷三十二年谱一", "bai": "", "page": 2736}, {"type": "meta", "wen": "卷三十三年谱二", "bai": "", "page": 2736}, {"type": "meta", "wen": "卷三十四年谱三", "bai": "", "page": 2736}, {"type": "meta", "wen": "卷三十五年谱附录一", "bai": "", "page": 2736}, {"type": "meta", "wen": "卷三十六年谱附录二", "bai": "", "page": 2736}, {"type": "heading", "wen": "卷三十七世德纪", "bai": "", "page": 2736}, {"type": "heading", "wen": "卷三十八世德纪附录", "bai": "", "page": 2736}, {"type": "heading", "wen": "卷三十九旧本未刊语录诗文补编", "bai": "", "page": 2736}, {"type": "heading", "wen": "卷四十旧本未刊祭文传记补编", "bai": "", "page": 2736}, {"type": "heading", "wen": "卷三十二", "bai": "", "page": 2737}]};
